	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 题目名字好长。&lt;/p&gt; &nbsp;
当年在考场上只会分块打表的题。
&nbsp;
前几天有人讲之后觉得大概可做。而且好像那个方法很优秀。
&nbsp;
于是我难得地去写了一回不用记搜且不记上界的数位dp。感觉这个玩意写出来很短，但是思考和调试的复杂度变高了。我觉得是状态定义变得不明确的原因。也许再补一些题就好了。
&nbsp;
考虑先让所有都合并到最低位，一个基础数位dp。（然后写丑了好久）
&nbsp;
然后考虑如果把一个数字的集合位置从p移动到p+1，设这个数字从低位到高位是a[0]..a[n-1]，那么贡献就是∑a[0..p]-∑a[p+1..n-1]。显然当p从右往左移动的时候它是会先负后正的。如果它负的话就减，否则就不玩了。可以发现它们互相不影响。于是对于每一个p单独计算一遍贡献就行了。
&nbsp;
然后还是没有原版跑得快。OTL。
&nbsp;
#define PROC "shop" #include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
typedef long long dint; #ifdef WIN32 #define lld &ldquo;%I64d&rdquo; #else #define lld &ldquo;%lld&rdquo; #endif #define _l (long long int)
const int maxn = 53; const int maxm = 509; const int mb = 253;
dint l, r; int n, m, bs, a[maxn];
dint dpBeginning() { static dint f[maxn], c[maxn], g[maxn], cr[maxn]; c[0] = bs; f[0] = 0; for (int i = 1; i &lt; n; ++ i) { c[i] = c[i - 1] * bs; f[i] = f[i - 1] * bs; for (int j = 1; j &lt; bs; ++ j) f[i] = f[i] + c[i - 1] * i * j; } cr[0] = g[0] = 0; cr[1] = a[0] + 1; g[1] = a[1] * cr[1]; for (int i = 2; i &lt;= n; ++ i) { cr[i] = g[i] = 0; for (int d = 0; d &lt; a[i - 1]; ++ d) { cr[i] += c[i - 2]; g[i] += f[i - 2] + c[i - 2] * (d * (i - 1) + a[i] * i); } cr[i] += cr[i - 1]; g[i] += cr[i - 1] * a[i] * i + g[i - 1]; } return g[n]; }
dint dp(dint v) { static dint c[maxn][maxm]; static dint cr[maxn][maxm]; m = 0; for (n = 0; v; v /= bs) a[n ++] = v % bs; a[n] = 0; m = n * bs; dint ans(dpBeginning()); //printf(lld &ldquo;\n&rdquo;, ans); for (int p = 1; p &lt; n; ++ p) { memset(c, 0, sizeof(c)); for (int i = 0; i &lt; bs; ++ i) c[0][mb - i] = 1; for (int i = 1; i &lt; n; ++ i) for (int j = mb - m; j &lt;= mb + m; ++ j) if (c[i - 1][j]) for (int d = 0; d &lt; bs; ++ d) { int t((i &lt; p) ? j - d : j + d); c[i][t] += c[i - 1][j]; } memset(cr, 0, sizeof(cr)); cr[0][mb - a[0]] = 1; for (int i = 1; i &lt;= n; ++ i) { for (int d = 0; d &lt; a[i - 1]; ++ d) if (i &gt; 1) { for (int j = mb - m; j &lt;= mb + m; ++ j) if (c[i - 2][j]) { int t((i - 1 &lt; p) ? j - d : j + d); t = (i &lt; p) ? t - a[i] : t + a[i]; cr[i][t] += c[i - 2][j]; } } else { int t((i &lt; p) ? mb - d - a[i] : mb - d + a[i]); ++ cr[i][t]; } for (int j = mb - m; j &lt;= mb + m; ++ j) if (cr[i - 1][j]) { int t((i &lt; p) ? j - a[i] : j + a[i]); cr[i][t] += cr[i - 1][j]; } } for (int i = 1; i &lt;= m; ++ i) ans -= cr[n][i + mb] * i; } return ans; }
int main() { #ifndef ONLINE_JUDGE freopen(PROC &ldquo;.in&rdquo;, &ldquo;r&rdquo;, stdin); freopen(PROC &ldquo;.out&rdquo;, &ldquo;w&rdquo;, stdout); #endif
scanf(lld lld &quot;%d&quot;, &amp;amp;l, &amp;amp;r, &amp;amp;bs); printf(lld &quot;\n&quot;, dp(r) - dp(l - 1)); }

summary:
&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 题目名字好长。&lt;/p&gt; &nbsp;
当年在考场上只会分块打表的题。
&nbsp;
前几天有人讲之后觉得大概可做。而且好像那个方法很优秀。
&nbsp;
于是我难得地去写了一回不用记搜且不记上界的数位dp。感觉这个玩意写出来很短，但是思考和调试的复杂度变高了。我觉得是状态定义变得不明确的原因。也许再补一些题就好了。
&nbsp;
考虑先让所有都合并到最低位，一个基础数位dp。（然后写丑了好久）
&nbsp;
然后考虑如果把一个数字的集合位置从p移动到p+1，设这个数字从低位到高位是a[0]..a[n-1]，那么贡献就是∑a[0..p]-∑a[p+1..n-1]。显然当p从右往左移动的时候它是会先负后正的。如果它负的话就减，否则就不玩了。可以发现它们互相不影响。于是对于每一个p单独计算一遍贡献就行了。
&nbsp;
然后还是没有原版跑得快。OTL。
&nbsp;
