	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 插头dp的练手题么。虽然之前还没写过哈密顿回路的题。&lt;/p&gt; &nbsp;
学习了一下广义括号法。发现状态数比之前记连通性的方法要少。仔细想想发现，两个连通的插头的顺序有关。不能存在1212这种东西。所以连通性的方法记了很多废状态。那把连通性方法改进一下会不会变得更快呢？可以研究一下。我觉得应该是等效了吧。
&nbsp;
今天的debug时间明显缩短了。虽然还是debug了老半天。然后怎么代码还是那么长。想起我每次都觉得把东西挤到一起看起来很不雅观，于是去写一堆找转移的函数。晕。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
typedef long long dint; #ifdef WIN32 #define lld &ldquo;%I64d&rdquo; #else #define lld &ldquo;%lld&rdquo; #endif #define _l (long long int)
const int maxn = 15; const int maxst = 50009;
#define mbit(x,y) ((x)&lt;&lt;((y)&lt;&lt;1)) #define gbit(x,y) (((x)&gt;&gt;((y)&lt;&lt;1))&amp;3) #define cbit(x,y) ((x)&amp;(~(3&lt;&lt;((y)&lt;&lt;1))))
int n, m, tots, slst[maxst]; bool mp[maxn][maxn]; dint f[2][maxst];
void dfsState(int l, int c, int z) { if (l == m + 1) { if (!c) slst[tots ++] = z; } else { dfsState(l + 1, c, z); dfsState(l + 1, c + 1, z | mbit(1, l)); if (c) dfsState(l + 1, c - 1, z | mbit(2, l)); } } void preState() { tots = 0; dfsState(0, 0, 0); sort(slst, slst + tots); } inline int fState(int s) { register int ret(lower_bound(slst, slst + tots, s) - slst); if (slst[ret] != s) puts(&ldquo;naive&rdquo;); return ret; }
#define inc(a,b) (a+=b) inline int brv(int x) { if (!x) return 0; else return (x == 1) ? 1 : -1; }
bool isEnd(int s, int y) { for (int i = 0; i &lt; y; ++ i) if (gbit(s, i)) return 0; for (int i = y + 2; i &lt;= m; ++ i) if (gbit(s, i)) return 0; return 1; } inline int mergePlug(int s, int y) { int p, c; if (gbit(s, y) != gbit(s, y + 1)) { s = cbit(s, y); s = cbit(s, y + 1); return fState(s); } else if (gbit(s, y) == 1) { for (c = 1, p = y + 1; c; ++ p, c += brv(gbit(s, p))); s = cbit(s, y); s = cbit(s, y + 1); s = cbit(s, p); return fState(s | mbit(1, p)); } else { for (c = -1, p = y; c; &ndash; p, c += brv(gbit(s, p))); s = cbit(s, y); s = cbit(s, y + 1); s = cbit(s, p); return fState(s | mbit(2, p)); } } inline int extPlugRight(int s, int y) { s |= mbit(gbit(s, y), y + 1); s = cbit(s, y); return fState(s); } inline int extPlugDown(int s, int y) { s |= mbit(gbit(s, y + 1), y); s = cbit(s, y + 1); return fState(s); } inline int forkPlug(int s, int y) { s |= mbit(1, y); s |= mbit(2, y + 1); return fState(s); } inline int nextRow(int s) { int r(0); for (int i = 0; i &lt; m; ++ i) r |= mbit(gbit(s, i), i + 1); return fState(r); }
