bool sw(0); scanf(&quot;%d%d&quot;, &amp;amp;n, &amp;amp;m); if (n &amp;lt; m) sw = 1; for (int i = 0; i &amp;lt; n; ++ i) for (int j = 0; j &amp;lt; m; ++ j) if (sw) scanf(&quot;%d&quot;, v[j] + i); else scanf(&quot;%d&quot;, v[i] + j); if (sw) swap(n, m); preState(); printf(&quot;%d\n&quot;, dp()); }

