	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 第六百道题一定要不水！虽然离第一页还有几十道题的距离。&lt;/p&gt; &nbsp;
很早之前见过的题吧。然后一直觉得特别难写所以都没写。以前写点不重复的仙人掌都觉得挺痛苦，更不要说这个了。
&nbsp;
现在想想还行，因为我yy出了化简的方法。先搞出dfs树。然后一个顶点如果是一个环里深度最浅的，那么称它为这个环的头。可以证明一个顶点最多在一个不以它为头的环上。把这个环记下来，其它的环都从这个顶点去找边来找就行了。这样的话可以比较节省代码量，写起来也比较明了。虽然还是比mhy长。
&nbsp;
然后因为我在最后一步dp的时候写了一个static的f数组，所以光荣了。debug了好久。晕。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
struct edge { int t, av; edge *next, *rv; }; struct ball { int l, *a, h; };
const int maxn = 50009; const int maxm = 200009; const int maxarr = 400009;
int n, m, cb, fb[maxn], d[maxn]; int f[maxn], ans, fd[maxn], fe[maxn]; int stc[maxn], tst; int ibuf_arr[maxarr], *ibuf(ibuf_arr); bool vis[maxn]; edge elst[maxm], *ep(elst), *head[maxn]; ball b[maxm];
inline edge* addEdge(int u, int v) { ep-&gt; t = v; ep-&gt; av = 1; ep-&gt; next = head[u]; return head[u] = ep ++; }
inline void upMax(int&amp; a, int b) { if (a &lt; b) a = b; }
void dfsBall(int p) { vis[p] = 1; stc[++ tst] = p; for (edge *e = head[p]; e; e = e-&gt; next) if (e-&gt; av) { e-&gt; rv-&gt; av = 0; if (vis[e-&gt; t] &amp;&amp; (!fb[p])) { e-&gt; av = 0; b[++ cb]. l = 0; b[cb]. a = ibuf; for (int i = tst; 1; &ndash; i) { b[cb]. a[b[cb]. l ++] = stc[i]; if (stc[i] != e-&gt; t) fb[stc[i]] = cb; else break; } b[cb]. h = e-&gt; t; ibuf += b[cb]. l; } else { d[e-&gt; t] = d[p] + 1; dfsBall(e-&gt; t); } } &ndash; tst; }
void downDP(int p) { fd[p] = fe[p] = 0; for (edge* e = head[p]; e; e = e-&gt; next) if (e-&gt; av) { if (fb[e-&gt; t] &amp;&amp; p == b[fb[e-&gt; t]]. h) { int bi(fb[e-&gt; t]), fl(0); for (int i = 0; i &lt; b[bi]. l; ++ i) if (b[bi]. a[i] != b[bi]. h) { int q(b[bi]. a[i]); downDP(q); upMax(fl, fd[q] + min(d[q] - d[p], b[bi]. l - d[q] + d[p])); } if (fl &gt; fd[p]) { fe[p] = fd[p]; fd[p] = fl; } else if (fl &gt; fe[p]) fe[p] = fl; } else if (!fb[p] || fb[p] != fb[e-&gt; t]) { downDP(e-&gt; t); int v(fd[e-&gt; t] + 1); if (v &gt; fd[p]) { fe[p] = fd[p]; fd[p] = v; } else if (v &gt; fe[p]) fe[p] = v; } } upMax(ans, fd[p] + fe[p]); }
#define modi(i) (((i)&gt;=b[bi].l)?((i)-b[bi].l):(i)) void upDP(int p, int u) { static int q[maxn &lt;&lt; 1], fu[maxn &lt;&lt; 1]; for (edge* e = head[p]; e; e = e-&gt; next) if (e-&gt; av) { if (fb[e-&gt; t] &amp;&amp; p == b[fb[e-&gt; t]]. h) { int bi(fb[e-&gt; t]), fl(0); int *f(ibuf); ibuf += b[bi]. l; for (int i = 0; i &lt; b[bi]. l; ++ i) { int q(b[bi]. a[i]); f[i] = 0; if (q == p) break; fu[i] = fd[q]; upMax(fl, fd[q] + min(d[q] - d[p], b[bi]. l - d[q] + d[p])); } if (fl == fd[p]) fu[b[bi]. l - 1] = max(u, fe[p]); else fu[b[bi]. l - 1] = max(u, fd[p]); int hd(0), tl(1), hl(b[bi]. l &gt;&gt; 1); q[0] = 0; for (int i = 1; i &lt; (b[bi]. l &lt;&lt; 1); ++ i) { int fi(modi(i)); while (hd &lt; tl &amp;&amp; i - q[hd] &gt; hl) ++ hd; if (hd &lt; tl) upMax(f[fi], fu[modi(q[hd])] + i - q[hd]); while (hd &lt; tl &amp;&amp; fu[modi(q[tl - 1])] - q[tl - 1] &lt;= fu[fi] - i) &ndash; tl; q[tl ++] = i; } hd = 0; tl = 1; q[0] = (b[bi]. l &lt;&lt; 1) - 1; for (int i = (b[bi]. l &lt;&lt; 1) - 2; i &gt;= 0; &ndash; i) { int fi(modi(i)); while (hd &lt; tl &amp;&amp; q[hd] - i &gt; hl) ++ hd; if (hd &lt; tl) upMax(f[fi], fu[modi(q[hd])] + q[hd] - i); while (hd &lt; tl &amp;&amp; fu[modi(q[tl - 1])] + q[tl - 1] &lt;= fu[fi] + i) &ndash; tl; q[tl ++] = i; } for (int i = 0; i &lt; b[bi]. l - 1; ++ i) { upMax(ans, f[i] + fd[b[bi]. a[i]]); upDP(b[bi]. a[i], f[i]); } ibuf -= b[bi]. l; } else if (!fb[p] || fb[e-&gt; t] != fb[p]) { int v((fd[e-&gt; t] + 1 == fd[p]) ? fe[p] : fd[p]); upDP(e-&gt; t, max(u, v) + 1); } } }
