	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 多老的省选题了。&lt;/p&gt; &nbsp;
就处理一下任意两个格子之间最少要经过几个1，如果小于等于t就更新答案。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cmath&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
#define mkword(x,y) (((x)&lt;&lt;16)|(y)) #define hiword(x) ((x)&gt;&gt;16) #define loword(x) ((x)&amp;0x0000ffff)
const int maxn = 33; const int maxnd = 909; const int movx[4] = {0, 0, 1, -1}; const int movy[4] = {1, -1, 0, 0};
typedef pair &lt;int, int&gt; dpr;
inline int sqr(int x) { return x * x; }
int n, m, t, d[maxn][maxn], ans; int mp[maxn][maxn]; dpr hp[maxnd &lt;&lt; 2];
void dijkstra(int i0, int j0) { int th(1); hp[0] = dpr(-mp[i0][j0], mkword(i0, j0)); memset(d, -1, sizeof(d)); while (th) { dpr g(hp[0]); pop_heap(hp, hp + th &ndash;); int x(hiword(g. second)), y(loword(g. second)); if (d[x][y] &gt; -1) continue; d[x][y] = - g. first; for (int mi = 0; mi &lt; 4; ++ mi) { int i(x + movx[mi]), j(y + movy[mi]); if (i &gt; 0 &amp;&amp; i &lt;= n &amp;&amp; j &gt; 0 &amp;&amp; j &lt;= m &amp;&amp; d[i][j] == -1) { hp[th] = dpr(g. first - mp[i][j], mkword(i, j)); push_heap(hp, hp + ++ th); } } } for (int i = 1; i &lt;= n; ++ i) for (int j = 1; j &lt;= m; ++ j) if (d[i][j] &lt;= t) { int ds(sqr(i - i0) + sqr(j - j0)); if (ds &gt; ans) ans = ds; } }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
scanf(&quot;%d%d%d&quot;, &amp;amp;n, &amp;amp;m, &amp;amp;t); for (int i = 1; i &amp;lt;= n; ++ i) { char g[maxn]; scanf(&quot;%s&quot;, g + 1); for (int j = 1; j &amp;lt;= m; ++ j) mp[i][j] = g[j] - 48; } ans = 0; for (int i = 1; i &amp;lt;= n; ++ i) for (int j = 1; j &amp;lt;= m; ++ j) dijkstra(i, j); printf(&quot;%.6lf\n&quot;, sqrt(ans)); }

