树上莫队的另一道题。比糖果公园好写到哪里去了。
&nbsp;
然后手写链表丑掉了导致调试半天+RE了一发。我还是太年轻了。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cmath&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
typedef struct node { int t; node *next; } edge; const int maxn = 50009; const int maxm = 100009; const int maxl = 17; node nlst[maxn], *np(nlst); struct chain { int sz; node *hd, *tl; chain() { hd = tl = 0; sz = 0; } inline void clear() { hd = tl = 0; sz = 0; } inline void push(int x) { np-&gt; t = x; np-&gt; next = 0; if (sz) { tl-&gt; next = np; tl = np; } else { hd = np; tl = np; } ++ np; ++ sz; } inline void merge(chain a) { if (a. sz) { if (sz) { tl-&gt; next = a. hd; tl = a. tl; } else { hd = a. hd; tl = a. tl; } sz += a. sz; } } }; struct query { int a, b, x, y, i; };
int n, m, bsz, ans[maxm], cnt[maxn], fb[maxn], col[maxn], tb; int d[maxn], ath[maxn][maxl]; edge elst[maxn &lt;&lt; 1], *ep(elst), *head[maxn]; query q[maxm];
inline bool operator &lt;(const query&amp; a, const query&amp; b) { return (fb[a. a] &lt; fb[b. a]) || (fb[a. a] == fb[b. a] &amp;&amp; fb[a. b] &lt; fb[b. b]); }
inline void addEdge(int u, int v) { ep-&gt; t = v; ep-&gt; next = head[u]; head[u] = ep ++; }
chain dfs(int p) { for (int i = 1; i &lt; maxl; ++ i) ath[p][i] = ath[ath[p][i - 1]][i - 1]; chain w; for (edge* e = head[p]; e; e = e-&gt; next) if (e-&gt; t != ath[p][0]) { ath[e-&gt; t][0] = p; d[e-&gt; t] = d[p] + 1; chain g(dfs(e-&gt; t)); w. merge(g); if (w. sz &gt;= bsz) { ++ tb; for (node* it = w. hd; it; it = it-&gt; next) fb[it-&gt; t] = tb; w. clear(); } } w. push(p); return w; } void divide() { d[0] = 1; tb = 0; chain g(dfs(0)); for (node* it = g. hd; it; it = it-&gt; next) fb[it-&gt; t] = tb; }
int LCA(int u, int v) { if (d[u] &lt; d[v]) swap(u, v); for (int i = maxl - 1; i &gt;= 0; &ndash; i) if (d[ath[u][i]] &gt;= d[v]) u = ath[u][i]; if (u == v) return u; for (int i = maxl - 1; i &gt;= 0; &ndash; i) if (ath[u][i] ^ ath[v][i]) { u = ath[u][i]; v = ath[v][i]; } return ath[u][0]; } inline void rmVertex(int p, int&amp; ans) { if (p &amp;&amp; ! &ndash; cnt[col[p]]) &ndash; ans; } inline void insVertex(int p, int&amp; ans) { if (p &amp;&amp; !(cnt[col[p]] ++)) ++ ans; } void moveVertex(int&amp; u, int v, int g, int&amp; ans) { int a(LCA(u, v)), t(LCA(a, g)); if (a == t) { int x(LCA(u, g)), y(LCA(v, g)); if (d[x] &gt; d[y]) t = x; else t = y; if (LCA(t, u) == t) { for (int p = g; p ^ t; p = ath[p][0]) insVertex(p, ans); for (int p = u; p ^ t; p = ath[p][0]) rmVertex(p, ans); } else { for (int p = g; p ^ t; p = ath[p][0]) insVertex(p, ans); for (int p = u; p ^ a; p = ath[p][0]) rmVertex(p, ans); for (int p = ath[t][0]; p ^ a; p = ath[p][0]) rmVertex(p, ans); rmVertex(a, ans); } } else { for (int p = u; p ^ a; p = ath[p][0]) rmVertex(p, ans); for (int p = g; p ^ t; p = ath[p][0]) insVertex(p, ans); insVertex(t, ans); for (int p = ath[a][0]; p ^ t; p = ath[p][0]) insVertex(p, ans); } u = g; } void cptMo() { int u(1), v(1), cans(1); memset(cnt, 0, sizeof(cnt)); cnt[col[1]] = 1; sort(q, q + m); for (int i = 0; i &lt; m; ++ i) { moveVertex(u, v, q[i]. a, cans); moveVertex(v, u, q[i]. b, cans); ans[q[i]. i] = cans; if ((q[i]. x || q[i]. y) &amp;&amp; q[i]. x != q[i]. y) ans[q[i]. i] -= (cnt[q[i]. x] &amp;&amp; cnt[q[i]. y]); } }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
scanf(&quot;%d%d&quot;, &amp;amp;n, &amp;amp;m); bsz = (int)pow(n, 0.5) + 1; for (int i = 1; i &amp;lt;= n; ++ i) scanf(&quot;%d&quot;, col + i); memset(head, 0, sizeof(head)); for (int i = 0; i &amp;lt; n; ++ i) { int u, v; scanf(&quot;%d%d&quot;, &amp;amp;u, &amp;amp;v); addEdge(u, v); addEdge(v, u); } for (int i = 0; i &amp;lt; m; ++ i) { scanf(&quot;%d%d%d%d&quot;, &amp;amp;q[i]. a, &amp;amp;q[i]. b, &amp;amp;q[i]. x, &amp;amp;q[i]. y); q[i]. i = i; } divide(); for (int i = 0; i &amp;lt; m; ++ i) if (fb[q[i]. a] &amp;gt; fb[q[i]. b]) swap(q[i]. a, q[i]. b); cptMo(); for (int i = 0; i &amp;lt; m; ++ i) printf(&quot;%d\n&quot;, ans[i]); }

