	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 最近很颓啊。&lt;/p&gt; &nbsp;
这题很久之前看过。当时以为是高消就没管。然后开坑之神idy做了之后仔细一想才知道不是。
&nbsp;
这题的做法是dp。首先因为边数少所以不用floyd，直接bfs预处理出所有t[i][j]表狼在i，兔子在j的时候狼下一步去哪。然后有一个结论是每一步两个玩意的距离至少缩短1，所以状态是不会有环的，这也是为啥可以不用高消。然后坑点是不能直接开状态队列，因为那不是拓补序。要先把每个点的入度算出来再跑dp。结局是我的代码超长。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
struct edge { int t; edge *next; };
#define mkword(x,y) (((x)&lt;&lt;16)|(y)) #define hiword(x) ((x)&gt;&gt;16) #define loword(x) ((x)&amp;0x0000ffff)
const int maxn = 1009; const int maxst = 1000009; const int inf = 0x3f3f3f3f;
int n, m, st, te, deg[maxn], d[maxn], t[maxn][maxn], ind[maxn][maxn]; edge elst[maxn &lt;&lt; 1], *ep(elst), *head[maxn]; double f[maxn][maxn], g[maxn][maxn], c[maxn], ans;
inline void addEdge(int u, int v) { ep-&gt; t = v; ep-&gt; next = head[u]; head[u] = ep ++; }
void bfs(int p0) { static int q[maxn]; int hd(0), tl(1); memset(d, -1, sizeof(d)); d[q[0] = p0] = 0; while (hd &lt; tl) { int p(q[hd ++]); for (edge* e = head[p]; e; e = e-&gt; next) if (d[e-&gt; t] == -1) { d[e-&gt; t] = d[p] + 1; q[tl ++] = e-&gt; t; } } for (int p = 1; p &lt;= n; ++ p) if (p == p0) { t[p][p] = p; } else { t[p][p0] = inf; for (edge* e = head[p]; e; e = e-&gt; next) if (d[p] == d[e-&gt; t] + 1 &amp;&amp; e-&gt; t &lt; t[p][p0]) t[p][p0] = e-&gt; t; } }
void dp() { static int q[maxst]; static bool iq[maxn][maxn]; int hd(0), tl(1); memset(iq, 0, sizeof(iq)); memset(f, 0, sizeof(f)); memset(g, 0, sizeof(g)); memset(ind, 0, sizeof(ind)); ans = 0; q[0] = mkword(st, te); iq[st][te] = 1; while (hd &lt; tl) { int i(hiword(q[hd])), j(loword(q[hd])), i0, j0; ++ hd; if (t[t[i][j]][j] != j) { for (edge* e = head[j]; e; e = e-&gt; next) { i0 = t[t[i][j]][j]; j0 = e-&gt; t; ++ ind[i0][j0]; int zn(mkword(i0, j0)); if (!iq[i0][j0]) { q[tl ++] = zn; iq[i0][j0] = 1; } } i0 = t[t[i][j]][j]; j0 = j; ++ ind[i0][j0]; int zn(mkword(i0, j0)); if (!iq[i0][j0]) { q[tl ++] = zn; iq[i0][j0] = 1; } } } memset(f, 0, sizeof(f)); memset(g, 0, sizeof(g)); g[st][te] = 1; ans = 0; q[0] = mkword(st, te); hd = 0; tl = 1; while (hd &lt; tl) { int i(hiword(q[hd])), j(loword(q[hd])), i0, j0; ++ hd; if (i == j) { ans += f[i][j]; } else if (t[t[i][j]][j] == j) { ans += f[i][j] + g[i][j]; } else { for (edge* e = head[j]; e; e = e-&gt; next) { i0 = t[t[i][j]][j]; j0 = e-&gt; t; g[i0][j0] += g[i][j] * c[j]; f[i0][j0] += (f[i][j] + g[i][j]) * c[j]; int zn(mkword(i0, j0)); &ndash; ind[i0][j0]; if (!ind[i0][j0]) q[tl ++] = zn; } i0 = t[t[i][j]][j]; j0 = j; g[i0][j0] += g[i][j] * c[j]; f[i0][j0] += (f[i][j] + g[i][j]) * c[j]; int zn(mkword(i0, j0)); &ndash; ind[i0][j0]; if (!ind[i0][j0]) q[tl ++] = zn; } } }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
scanf(&quot;%d%d%d%d&quot;, &amp;amp;n, &amp;amp;m, &amp;amp;st, &amp;amp;te); memset(d, 0x3f, sizeof(d)); memset(deg, 0, sizeof(deg)); for (int i = 0; i &amp;lt; m; ++ i) { int u, v; scanf(&quot;%d%d&quot;, &amp;amp;u, &amp;amp;v); addEdge(u, v); addEdge(v, u); ++ deg[u]; ++ deg[v]; } for (int i = 1; i &amp;lt;= n; ++ i) { bfs(i); c[i] = 1.0 / (deg[i] + 1); } dp(); printf(&quot;%.3lf\n&quot;, ans); }

