scanf(&quot;%d%d&quot;, &amp;amp;n, &amp;amp;m); memset(w, 0, sizeof(w)); t = n * (n - 1) * (n - 2) / 6; for (int i = 0; i &amp;lt; m; ++ i) { int u, v; scanf(&quot;%d%d&quot;, &amp;amp;u, &amp;amp;v); ++ w[u]; ++ w[v]; } c = 0; for (int i = 1; i &amp;lt;= n; ++ i) c += w[i] * (n - w[i] - 1); c &amp;gt;&amp;gt;= 1; printf(&quot;%d\n&quot;, t - c); }

