	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 多少年前的坑了。&lt;/p&gt; &nbsp;
用mac写的第一篇题解呢。
&nbsp;
环套树DP。先把树上的情况处理了，然后枚举取不取环上的第一个。
&nbsp;
要注意会有重边的情况，比较恶心。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cctype&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
const int buf_len = 4000; char buf[buf_len], *bufb(buf), *bufe(buf + 1); #define readBuf() { if (++ bufb == bufe) bufe = (bufb = buf) + fread(buf, 1, sizeof(buf), stdin); } #define readInt(x) { register int s(0); do { readBuf(); } while (!isdigit(*bufb)); do { s = s * 10 + *bufb - 48; readBuf(); } while (isdigit(*bufb)); x = s; }
typedef long long dint; #ifdef WIN32 #define lld &ldquo;%I64d&rdquo; #else #define lld &ldquo;%lld&rdquo; #endif
struct edge { int t; edge *next; };
const int maxn = 1000009;
int n, v[maxn]; int stc[maxn], tst, lpp[maxn], tlp; int vis[maxn], onl[maxn]; dint f[maxn], g[maxn]; edge elst[maxn &lt;&lt; 1], *ep(elst), *head[maxn];
inline void addEdge(int u, int v) { ep-&gt; t = v; ep-&gt; next = head[u]; head[u] = ep ++; }
void dfsLoop(int p, int fr) { vis[p] = fr + 1; stc[tst ++] = p; for (edge* e = head[p]; e; e = e-&gt; next) if (e-&gt; t != fr) { if (!vis[e-&gt; t]) { dfsLoop(e-&gt; t, p); } else if (vis[e-&gt; t] &amp;&amp; vis[e-&gt; t] != p + 1) { if (onl[p]) continue; tlp = 0; do { &ndash; tst; lpp[tlp ++] = stc[tst]; onl[stc[tst]] = 1; } while (stc[tst] != e-&gt; t); } } if (stc[tst - 1] == p) &ndash; tst; }
void dfsDP(int p, int fr) { f[p] = 0; g[p] = v[p]; vis[p] = -1; for (edge* e = head[p]; e; e = e-&gt; next) if (e-&gt; t != fr &amp;&amp; !onl[e-&gt; t] &amp;&amp; vis[e-&gt; t] != -1) { dfsDP(e-&gt; t, p); f[p] += max(f[e-&gt; t], g[e-&gt; t]); g[p] += f[e-&gt; t]; } }
dint calcCC(int p) { tst = 0; tlp = 0; dfsLoop(p, 0); if (!tlp) lpp[tlp ++] = p; for (int i = 0; i &lt; tlp; ++ i) dfsDP(lpp[i], 0); dint s0(0), s1(0); if (tlp &lt; 3) { for (int i = 0; i &lt; tlp; ++ i) s0 = max(s0, g[lpp[i]] - f[lpp[i]]); for (int i = 0; i &lt; tlp; ++ i) s0 += f[lpp[i]]; } else { dint f0(g[lpp[0]] + f[lpp[1]] + f[lpp[tlp - 1]]), g0(f0); for (int i = 2; i &lt; tlp - 1; ++ i) { dint f1(f[lpp[i]] + max(f0, g0)), g1(g[lpp[i]] + f0); f0 = f1; g0 = g1; } s0 = max(f0, g0); } if (tlp &lt; 3) { s1 = s0; } else { dint f0(f[lpp[0]]), g0(f0); for (int i = 1; i &lt; tlp; ++ i) { dint f1(f[lpp[i]] + max(f0, g0)), g1(g[lpp[i]] + f0); f0 = f1; g0 = g1; } s1 = max(g0, f0); } return max(s0, s1); }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
readInt(n); memset(head, 0, sizeof(head)); for (int i = 1; i &amp;lt;= n; ++ i) { int x; readInt(v[i]); readInt(x); addEdge(i, x); addEdge(x, i); } memset(vis, 0, sizeof(vis)); memset(onl, 0, sizeof(onl)); dint ans(0); for (int i = 1; i &amp;lt;= n; ++ i) if (!vis[i]) ans += calcCC(i); printf(lld &quot;\n&quot;, ans); }

