	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 今天wc讲的题。主要其实是用拟阵来证明贪心的正确性。就构造一下就好了。不选的集合构成一个拟阵的基，如果基不能异或出0就是线性无关的。然后按照拟阵的贪心方法挨个加。&lt;/p&gt; &nbsp;
策略是从大到小排个序能不选就不选，用异或消元来判断一下就好了。许久没有写了，还好没有搞忘。
&nbsp;
代码还是比较短的，开心ing。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
typedef long long dint; #ifdef WIN32 #define lld &ldquo;%I64d&rdquo; #else #define lld &ldquo;%lld&rdquo; #endif #define _l (long long int)
const int maxn = 109;
int n, a[maxn], b[maxn], c[maxn], t; dint s;
bool hasZero() { for (int i = 0; i &lt; t; ++ i) b[i] = c[i]; for (int i = 31, j = 0; i &gt;= 0 &amp;&amp; j &lt; t; &ndash; i) { for (int k = j; k &lt; n; ++ k) if ((b[k] &gt;&gt; i) &amp; 1) { swap(b[k], b[j]); break; } if ((b[j] &gt;&gt; i) &amp; 1) { for (int k = j + 1; k &lt; n; ++ k) if ((b[k] &gt;&gt; i) &amp; 1) { b[k] ^= b[j]; if (!b[k]) return 1; } ++ j; } } return 0; }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
s = 0; scanf(&quot;%d&quot;, &amp;amp;n); for (int i = 0; i &amp;lt; n; ++ i) scanf(&quot;%d&quot;, a + i); sort(a, a + n); t = 0; for (int i = n - 1; i &amp;gt;= 0; -- i) { c[t ++] = a[i]; if (hasZero()) { -- t; s += a[i]; } } printf(lld &quot;\n&quot;, s); }

