#define upmax(a,b) { if (a &lt; b) a = b; } #define mkpos(x,y) (((x)&lt;&lt;16)|(y)) #define getx(a) ((a)&gt;&gt;16) #define gety(a) ((a)&amp;0x0000ffff) #define nid(x,y) (((x)*n)+(y))
struct disjoint_set { int r[maxn], h[maxn]; int vst[maxn], rst[maxn], ust[maxn], hst[maxn], tst; inline disjoint_set() { tst = 0; } void init(int n) { for (int i = 0; i &lt; n; ++ i) r[i] = i, h[i] = 1; } int getRoot(int x) { for (; r[x] ^ x; x = r[x]); return x; } inline void merge(int u, int v) { u = getRoot(u), v = getRoot(v); if (h[u] &lt; h[v]) swap(u, v); vst[++ tst] = v; rst[tst] = r[v]; r[v] = u; ust[tst] = u; hst[tst] = h[u]; upmax(h[u], h[v] + 1); } void recover(int x) { while (tst &gt; x) { r[vst[tst]] = rst[tst]; h[vst[tst]] = hst[tst]; &ndash; tst; } } };
