#define midp(p) ((p-&gt;l+p-&gt;r)&gt;&gt;1)
inline seg* sgtBuild(int l, int r) { seg* p(sp ++); p-&gt; l = l; p-&gt; r = r; p-&gt; head = 0; if (l + 1 &lt; r) { p-&gt; ls = sgtBuild(l, midp(p)); p-&gt; rs = sgtBuild(midp(p), r); } return p; } inline void sgtIns(seg* p, int l, int r, int ps, int cl) { if (p-&gt; l == l &amp;&amp; p-&gt; r == r) { np-&gt; v = ps; np-&gt; c = cl; np-&gt; next = p-&gt; head; p-&gt; head = np ++; } else if (r &lt;= midp(p)) sgtIns(p-&gt; ls, l, r, ps, cl); else if (l &gt;= midp(p)) sgtIns(p-&gt; rs, l, r, ps, cl); else { sgtIns(p-&gt; ls, l, midp(p), ps, cl); sgtIns(p-&gt; rs, midp(p), r, ps, cl); } }
disjoint_set r;
