其实思路比较简单。直接链剖dfs序上把所有区间找出来swap就好了。不过代码实现起来还是比较麻烦的，很容易绕晕。加上smt久了没写手生了，于是就调了一晚上。唉，我还是太年轻了。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
struct node { int v, s, sz, w, rv; node ls, rs; inline void update() { sz = 1; s = v; if (ls) { sz += ls-&gt; sz; s += ls-&gt; s; } if (rs) { sz += rs-&gt; sz; s += rs-&gt; s; } } inline void fix() { if (rv) { swap(ls, rs); if (ls) ls-&gt; rv ^= 1; if (rs) rs-&gt; rv ^= 1; rv = 0; } } }; typedef pair &lt;node, node&gt; npr;
const int maxn = 80009;
#define szof(p) ((p)?(p-&gt;sz):0) #define sof(p) ((p)?(p-&gt;s):0) node nlst[maxn &lt;&lt; 1], np(nlst); node newNode(int v) { np-&gt; ls = np-&gt; rs = 0; np-&gt; v = np-&gt; s = v; np-&gt; sz = 1; np-&gt; rv = 0; #ifdef WIN32 np-&gt; w = (rand() &lt;&lt; 16) | rand(); #else np-&gt; w = rand(); #endif return np ++; } node* merge(node* p, node* q) { if (p) p-&gt; fix(); else return q; if (q) q-&gt; fix(); else return p; if (p-&gt; w &gt; q-&gt; w) { p-&gt; rs = merge(p-&gt; rs, q); p-&gt; update(); return p; } else { q-&gt; ls = merge(p, q-&gt; ls); q-&gt; update(); return q; } } npr split(node* p, int k) { if (!k) return npr(0, p); else if (!p || p-&gt; sz == k) return npr(p, 0); else { p-&gt; fix(); if (k &lt;= szof(p-&gt; ls)) { npr g(split(p-&gt; ls, k)); p-&gt; ls = g. second; p-&gt; update(); return npr(g. first, p); } else { npr g(split(p-&gt; rs, k - szof(p-&gt; ls) - 1)); p-&gt; rs = g. first; p-&gt; update(); return npr(p, g. second); } } } int smtQry(node* p, int k) { int s(0); while (p &amp;&amp; k) { p-&gt; fix(); if (k &lt;= szof(p-&gt; ls)) p = p-&gt; ls; else s += sof(p-&gt; ls) + p-&gt; v, k -= szof(p-&gt; ls) + 1, p = p-&gt; rs; } return s; }
struct edge { int t; edge *next; }; edge *head[maxn], elst[maxn &lt;&lt; 1], *ep(elst); inline void addEdge(int u, int v) { ep-&gt; t = v; ep-&gt; next = head[u]; head[u] = ep ++; }
int v[maxn], n, m; int tc, fa[maxn], d[maxn], sz[maxn], fs[maxn], fc[maxn], ch[maxn]; int dfb[maxn], dfo[maxn]; node *rt, *remp;
void divide() { static int stc[maxn]; int tst(1), dfn(0); memset(fa, 0, sizeof(fa)); stc[tst] = 1; while (tst) { int p(stc[tst &ndash;]); dfo[++ dfn] = p; for (edge* e = head[p]; e; e = e-&gt; next) if (e-&gt; t ^ fa[p]) { fa[e-&gt; t] = p; d[e-&gt; t] = d[p] + 1; stc[++ tst] = e-&gt; t; } } tc = 0; for (int i = n; i; &ndash; i) { int p(dfo[i]); fs[p] = -1; sz[p] = 1; for (edge* e = head[p]; e; e = e-&gt; next) if (fa[e-&gt; t] == p) { sz[p] += sz[e-&gt; t]; if (fs[p] == -1 || sz[e-&gt; t] &gt; sz[fs[p]]) fs[p] = e-&gt; t; } if (fs[p] == -1) fc[p] = ++ tc; else fc[p] = fc[fs[p]]; ch[fc[p]] = p; } stc[tst = 1] = 1; dfn = 0; while (tst) { int p(stc[tst &ndash;]); dfo[++ dfn] = p; dfb[p] = dfn; for (edge* e = head[p]; e; e = e-&gt; next) if (fa[e-&gt; t] == p &amp;&amp; e-&gt; t != fs[p]) stc[++ tst] = e-&gt; t; if (fs[p] != -1) stc[++ tst] = fs[p]; } rt = 0; for (int i = 1; i &lt;= n; ++ i) rt = merge(rt, newNode(v[dfo[i]])); remp = 0; for (int i = 1; i &lt;= n; ++ i) remp = merge(remp, newNode(-1)); }
int query(int u, int v) { int s(0); while (fc[u] ^ fc[v]) if (d[ch[fc[u]]] &gt; d[ch[fc[v]]]) { s += smtQry(rt, dfb[u]) - smtQry(rt, dfb[ch[fc[u]]] - 1); u = fa[ch[fc[u]]]; } else { s += smtQry(rt, dfb[v]) - smtQry(rt, dfb[ch[fc[v]]] - 1); v = fa[ch[fc[v]]]; } if (d[u] &lt; d[v]) s += smtQry(rt, dfb[v]) - smtQry(rt, dfb[u] - 1); else s += smtQry(rt, dfb[u]) - smtQry(rt, dfb[v] - 1); return s; }
bool checkTree(node* p, char e) { if (p) { if (p-&gt; rv) { checkTree(p-&gt; rs, 32); printf(&quot;%d%c&quot;, p-&gt; v, e); checkTree(p-&gt; ls, 32); } else { checkTree(p-&gt; ls, 32); printf(&quot;%d%c&quot;, p-&gt; v, e); checkTree(p-&gt; rs, 32); } } return 0; }
typedef pair &lt;int, int&gt; rpr; rpr ra[maxn], rb[maxn]; void flip(int u, int v) { int tra(0), trb(0); while (fc[u] ^ fc[v]) { if (d[ch[fc[u]]] &gt; d[ch[fc[v]]]) { ra[tra ++] = rpr(dfb[ch[fc[u]]], dfb[u]); u = fa[ch[fc[u]]]; } else { rb[trb ++] = rpr(dfb[ch[fc[v]]], dfb[v]); v = fa[ch[fc[v]]]; } } if (d[u] &lt; d[v]) rb[trb ++] = rpr(dfb[u], dfb[v]); else ra[tra ++] = rpr(dfb[v], dfb[u]); node *cr(0); for (int i = 0; i &lt; tra; ++ i) { npr x = split(rt, ra[i]. first - 1); npr y = split(x. second, ra[i]. second - ra[i]. first + 1); cr = merge(y. first, cr); npr z = split(remp, ra[i]. second - ra[i]. first + 1); remp = z. second; x. second = merge(z. first, y. second); rt = merge(x. first, x. second); } if (cr) cr-&gt; rv ^= 1; for (int i = trb - 1; i &gt;= 0; &ndash; i) { npr x = split(rt, rb[i]. first - 1); npr y = split(x. second, rb[i]. second - rb[i]. first + 1); cr = merge(cr, y. first); npr z = split(remp, rb[i]. second - rb[i]. first + 1); remp = z. second; x. second = merge(z. first, y. second); rt = merge(x. first, x. second); } if (cr) cr-&gt; rv ^= 1; for (int i = 0; i &lt; tra; ++ i) { npr x = split(rt, ra[i]. first - 1); npr y = split(x. second, ra[i]. second - ra[i]. first + 1); npr z = split(cr, ra[i]. second - ra[i]. first + 1); cr = z. second; if (z. first) z. first-&gt; rv ^= 1; x. second = merge(z. first, y. second); rt = merge(x. first, x. second); remp = merge(remp, y. first); } if (cr) cr-&gt; rv ^= 1; for (int i = 0; i &lt; trb; ++ i) { npr x = split(rt, rb[i]. first - 1); npr y = split(x. second, rb[i]. second - rb[i]. first + 1); npr z = split(cr, rb[i]. second - rb[i]. first + 1); cr = z. second; if (z. first) z. first-&gt; rv ^= 1; x. second = merge(z. first, y. second); rt = merge(x. first, x. second); remp = merge(remp, y. first); } }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
memset(head, 0, sizeof(head)); scanf(&quot;%d%d&quot;, &amp;amp;n, &amp;amp;m); for (int i = 1; i &amp;lt;= n; ++ i) scanf(&quot;%d&quot;, v + i); for (int i = 1; i &amp;lt; n; ++ i) { int u, v; scanf(&quot;%d%d&quot;, &amp;amp;u, &amp;amp;v); addEdge(u, v); addEdge(v, u); } divide(); while (m --) { int opt, u, v; scanf(&quot;%d%d%d&quot;, &amp;amp;opt, &amp;amp;u, &amp;amp;v); if (opt == 0) printf(&quot;%d\n&quot;, query(u, v)); else flip(u, v); } }

