 想起去年在考场上完全没有思路不想写数据结构于是骗了30分。现在想想当初还是naive。
&nbsp;
这题看上去就是点分治。因为要动态加点所以要动态。然后利用替罪羊树的方法重构树上的一团东西（不能叫团，否则命名重复了）。
&nbsp;
本来以为要写很久，结果也没写多久。奇怪的是，把maintain展开到insert里面之后就跑得飞快了，否则过不到而且根本跑不下来9和10。又丑了郁闷。
&nbsp;
#include &lt;cstdio&gt; #include &lt;cctype&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
const int buf_len = 4000; const size_t buf_size = buf_len * sizeof(char); char buf[buf_len], *bufb(buf), *bufe(buf + 1); #define readBuf() { if (++ bufb == bufe) bufe = (bufb = buf) + fread(buf, 1, buf_size, stdin); } #define readInt(x) { register int s(0); do { readBuf(); } while (!isdigit(*bufb)); do { s = s * 10 + *bufb - 48; readBuf(); } while (isdigit(*bufb)); x = s; }
struct edge { int t, v; edge *next; }; struct sbt_node { int vl, sz; sbt_node *ls, *rs; };
typedef long long dint;
#ifdef WIN32 #define lld &ldquo;%I64d&rdquo; #else #define lld &ldquo;%lld&rdquo; #endif #define _l (long long int)
const int maxn = 100009; const int fmod = 1e9; const int maxl = 19; const int maxnd = maxn * maxl * 2; const int balc = 3; const double ublim = 0.9; const int inf = 0x3f3f3f3f;
dint lans; int n; int ath[maxn][maxl], drt[maxn], dep[maxn]; int bd[maxn], bsz[maxn], bfa[maxn], br[maxn], r[maxn]; int stsz[maxn], vis[maxn], vist; sbt_node slst[maxnd], *sstc[maxnd], **sp, *brt[maxn], *prt[maxn]; edge *head[maxn], elst[maxn &lt;&lt; 1], *ep(elst);
void pre() { for (int i = 0; i &lt; maxnd; ++ i) { sstc[i] = slst + i; slst[i]. ls = slst[i]. rs = 0; } sp = sstc; vist = 0; memset(vis, 0, sizeof(vis)); }
inline void addEdge(int u, int v, int w) { ep-&gt; t = v; ep-&gt; v = w; ep-&gt; next = head[u]; head[u] = ep ++; }
#define szof(p) ((p)?(p-&gt;sz):0) inline sbt_node* allocNode() { static sbt_node* ret; ret = (sp ++); if (ret-&gt; ls) (&ndash; sp) = ret-&gt; ls; if (ret-&gt; rs) (&ndash; sp) = ret-&gt; rs; return ret; } inline void lRot(sbt_node &amp;p) { register sbt_node q(p-&gt; ls); p-&gt; ls = q-&gt; rs; q-&gt; rs = p; q-&gt; sz = p-&gt; sz; p-&gt; sz = szof(p-&gt; ls) + szof(p-&gt; rs) + 1; p = q; } inline void rRot(sbt_node &amp;p) { register sbt_node* q(p-&gt; rs); p-&gt; rs = q-&gt; ls; q-&gt; ls = p; q-&gt; sz = p-&gt; sz; p-&gt; sz = szof(p-&gt; ls) + szof(p-&gt; rs) + 1; p = q; } inline void sbtIns(sbt_node* &amp;p, int v0) { if (!p) { p = allocNode(); p-&gt; ls = p-&gt; rs = 0; p-&gt; sz = 1; p-&gt; vl = v0; } else { ++ p-&gt; sz; if (v0 &lt; p-&gt; vl) { sbtIns(p-&gt; ls, v0); if (szof(p-&gt; ls) &gt; szof(p-&gt; rs) + balc) lRot(p); } else { sbtIns(p-&gt; rs, v0); if (szof(p-&gt; ls) + balc &lt; szof(p-&gt; rs)) rRot(p); } } } int sbtCntLower(sbt_node* p, int v0) { int s(0); while (p) if (v0 &lt; p-&gt; vl) p = p-&gt; ls; else s += szof(p-&gt; ls) + 1, p = p-&gt; rs; return s; }
int LCA(int u, int v) { if (dep[u] &lt; dep[v]) swap(u, v); for (int i = maxl - 1; i &gt;= 0; &ndash; i) if (dep[ath[u][i]] &gt;= dep[v]) u = ath[u][i]; if (u == v) return u; for (int i = maxl - 1; i &gt;= 0; &ndash; i) if (ath[u][i] ^ ath[v][i]) { u = ath[u][i]; v = ath[v][i]; } return ath[u][0]; } inline int dist(int u, int v) { int a(LCA(u, v)); return drt[u] + drt[v] - drt[a] * 2; }
void insEach(sbt_node* q, sbt_node* &amp;x, int mn) { static sbt_node* stc[maxn]; int tst(1); stc[1] = q; while (tst) { sbt_node* p(stc[tst &ndash;]); sbtIns(x, p-&gt; vl + mn); if (p-&gt; ls) stc[++ tst] = p-&gt; ls; if (p-&gt; rs) stc[++ tst] = p-&gt; rs; } } int build(int pbd, int pbr, int pbf) { static int q[maxn], fr[maxn], dst[maxn]; int hd(0), tl(1), ct(0), cs(inf); q[0] = pbr; fr[pbr] = 0; dst[pbr] = 0; while (hd &lt; tl) { int p(q[hd ++]); for (edge* e = head[p]; e; e = e-&gt; next) if (bd[e-&gt; t] == inf &amp;&amp; e-&gt; t != fr[p]) { fr[e-&gt; t] = p; dst[e-&gt; t] = dst[p] + e-&gt; v; q[tl ++] = e-&gt; t; } } for (int ti = tl - 1, p; ti &gt;= 0; &ndash; ti) { int ms(1); p = q[ti]; stsz[p] = 1; for (edge* e = head[p]; e; e = e-&gt; next) if (bd[e-&gt; t] == inf &amp;&amp; e-&gt; t != fr[p]) { stsz[p] += stsz[e-&gt; t]; if (ms &lt; stsz[e-&gt; t]) ms = stsz[e-&gt; t]; } if (ms &lt; tl - stsz[p]) ms = tl - stsz[p]; if (ms &lt; cs) { cs = ms; ct = p; } } for (int ti = 0, p; ti &lt; tl; ++ ti) { p = q[ti]; sbtIns(prt[ct], dst[p] - r[p]); } bd[ct] = pbd; bsz[ct] = tl; bfa[ct] = pbf; br[ct] = pbr; sbtIns(brt[ct], -r[ct]); for (edge* e = head[ct]; e; e = e-&gt; next) if (bd[e-&gt; t] == inf) { int nr(build(pbd + 1, e-&gt; t, ct)); insEach(prt[nr], brt[ct], e-&gt; v); } return ct; }
void rebuild(int p0, int pbd, int pbr, int pbf) { static int q[maxn]; int hd(0), tl(1); ++ vist; vis[p0] = vist; q[0] = p0; while (hd &lt; tl) { int p(q[hd ++]); *(&ndash; sp) = brt[p]; (&ndash; sp) = prt[p]; brt[p] = 0; prt[p] = 0; for (edge e = head[p]; e; e = e-&gt; next) if (bd[e-&gt; t] &gt; pbd &amp;&amp; vis[e-&gt; t] &lt; vist) { vis[e-&gt; t] = vist; q[tl ++] = e-&gt; t; } } for (int i = 0; i &lt; tl; ++ i) bd[q[i]] = inf; build(pbd, pbr, pbf); }
void addNode(int p) { brt[p] = 0; sbtIns(brt[p], -r[p]); prt[p] = 0; sbtIns(prt[p], -r[p]); if (p == 1) { bd[p] = 1; bsz[p] = 1; bfa[p] = 0; br[p] = 1; } else { register int fa(ath[p][0]); bd[p] = bd[fa] + 1; bsz[p] = 1; bfa[p] = fa; br[p] = p; int q(fa), l(p), ubp, dt(0); double ubv(0); while (q) { ++ bsz[q]; if ((double)bsz[l] / bsz[q] &gt; ubv) { ubv = (double)bsz[l] / bsz[q]; ubp = q; } int d0(dist(p, q)); sbtIns(brt[q], d0 - r[p]); sbtIns(prt[q], dist(br[q], p) - r[p]); dt += sbtCntLower(brt[q], r[p] - d0) - sbtCntLower(prt[l], r[p] - d0 - dist(br[l], q)); l = q; q = bfa[q]; } lans += dt; if (ubv &gt; ublim) rebuild(ubp, bd[ubp], br[ubp], bfa[ubp]); } }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
pre(); readInt(n); readInt(n); lans = 0; for (int i = 1; i &amp;lt;= n; ++ i) { int fa; readInt(fa); readInt(drt[i]); readInt(r[i]); if (i &amp;gt; 1) { fa ^= lans % fmod; dep[i] = dep[fa] + 1; addEdge(fa, i, drt[i]); addEdge(i, fa, drt[i]); drt[i] += drt[fa]; ath[i][0] = fa; for (int j = 1; j &amp;lt; maxl; ++ j) ath[i][j] = ath[ath[i][j - 1]][j - 1]; } else { dep[i] = 1; } addNode(i); printf(lld &quot;\n&quot;, lans); } }

