	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 老久之前就看到过的题，不过不会做。今天晚上也是花了差不多俩小时才调过，虽然大概一个半小时都在纠结二分怎么写的问题。我没救了。&lt;/p&gt; &nbsp;
考虑经典的中位数二分，是把≤x的数字取-1，&gt;x的数取1，然后算最大子串看是否大于-1或1中的某一个，具体要看题目要求偶数是取上整还是下整什么的。
&nbsp;
然后这题就把所有东西排序之后拿可持久化线段树把这个序列搞出来，然后照着之前的思路二分就好了。线段树用来维护最大和最小前缀和。
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
struct dat { int sm, s; }; struct seg { int l, r; dat v[2]; seg *ls, *rs; };
#define _l (long long int)
typedef pair &lt;int, int&gt; vpr; typedef dat(*dat_mf)(const dat&amp;, const dat&amp;);
const int maxn = 20009; const int maxnd = maxn * 19; const dat null_str = {0, 0}; const dat neg_str0 = {-1, -1}; const dat neg_str1 = {-1, -1}; const dat pos_str0 = {1, 1}; const dat pos_str1 = {1, 1};
vpr a[maxn]; int n, m, q[4], lans, maxv; seg slst[maxnd], *sp(slst), *rt[maxn];
#define mid(p) ((p-&gt;l+p-&gt;r)&gt;&gt;1)
dat ret; inline dat merd0(const dat&amp; a, const dat&amp; b) { ret. sm = a. sm + b. sm; ret. s = min(a. s, a. sm + b. s); return ret; } inline dat merd1(const dat&amp; a, const dat&amp; b) { ret. sm = a. sm + b. sm; ret. s = max(a. s, a. sm + b. s); return ret; } const dat_mf dmf[2] = {merd0, merd1}; inline dat addSum(const int&amp; v, const dat&amp; a) { ret. s = a. s + v; ret. sm = a. sm + v; return ret; }
seg* sgtBuild(int l, int r) { seg *p(sp ++); p-&gt; l = l; p-&gt; r = r; if (l + 1 == r) { p-&gt; v[0] = neg_str0; p-&gt; v[1] = neg_str1; } else { p-&gt; ls = sgtBuild(l, mid(p)); p-&gt; rs = sgtBuild(mid(p), r); p-&gt; v[0] = merd0(p-&gt; ls-&gt; v[0], p-&gt; rs-&gt; v[0]); p-&gt; v[1] = merd1(p-&gt; ls-&gt; v[1], p-&gt; rs-&gt; v[1]); } return p; }
seg* sgtChg(seg* q, int p0) { seg* p(sp ++); p-&gt; l = q-&gt; l; p-&gt; r = q-&gt; r; if (p-&gt; l + 1 == p-&gt; r) { p-&gt; v[0] = pos_str0; p-&gt; v[1] = pos_str1; } else { if (p0 &lt; mid(p)) { p-&gt; ls = sgtChg(q-&gt; ls, p0); p-&gt; rs = q-&gt; rs; } else { p-&gt; ls = q-&gt; ls; p-&gt; rs = sgtChg(q-&gt; rs, p0); } p-&gt; v[0] = merd0(p-&gt; ls-&gt; v[0], p-&gt; rs-&gt; v[0]); p-&gt; v[1] = merd1(p-&gt; ls-&gt; v[1], p-&gt; rs-&gt; v[1]); } return p; }
int qv; dat sgtQry(seg* p, int l, int r) { if (p-&gt; l == l &amp;&amp; p-&gt; r == r) return p-&gt; v[qv]; else if (r &lt;= mid(p)) return sgtQry(p-&gt; ls, l, r); else if (l &gt;= mid(p)) return addSum(p-&gt; ls-&gt; v[0]. sm, sgtQry(p-&gt; rs, l, r)); else return dmf[qv](sgtQry(p-&gt; ls, l, mid(p)), sgtQry(p-&gt; rs, mid(p), r)); }
void pstat(seg* p, bool sr = 1) { if (p-&gt; l + 1 == p-&gt; r) printf(&quot;%d &ldquo;, p-&gt; v[0]. sm); else { pstat(p-&gt; ls, 0); pstat(p-&gt; rs, 0); } if (sr) putchar(10); }
int minSum(int x) { int v0, v1; qv = 1; if (q[0] == 0) v0 = max(0, sgtQry(rt[x], 0, q[1]). s); else v0 = sgtQry(rt[x], q[0] - 1, q[1]). s; qv = 0; v1 = sgtQry(rt[x], q[2], q[3] + 1). s; return v1 - v0; }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
