	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 听说是水水的splay，果然是。&lt;/p&gt; &nbsp;
乍一看要用lct，然后因为度数只有2，所以肯定是一条链。然后就直接用splay来维护。然后因为少写了句splay(v)导致多调了至少一节课的时间。我没救了。
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; #include &lt;map&gt; using namespace std;
#define upmax(a,b) { if (a &lt; b) a = b; }
struct splay_node { int vl, vm, rv; splay_node *pt, *ls, *rs; inline void update() { vm = vl; if (ls) upmax(vm, ls-&gt; vm); if (rs) upmax(vm, rs-&gt; vm); } inline void fix() { if (rv) { swap(ls, rs); if (ls) ls-&gt; rv ^= 1; if (rs) rs-&gt; rv ^= 1; rv = 0; } } };
typedef pair &lt;int, int&gt; edge; typedef pair &lt;edge, int&gt; mpr; typedef map &lt;edge, int&gt; emap;
const int maxn = 200009; const int maxc = 13;
#define nid(p,c) ((p)+(c)*n) #define eid(e) ((e)+eb)
splay_node slst[maxn], *sr[maxn]; int v[maxn], n, m, c, q, eb, nc[maxn][maxc], ce[maxn]; emap el;
inline void rot(splay_node* q) { splay_node *p(q-&gt; pt), *a(p-&gt; pt); if (a) { if (p == a-&gt; ls) a-&gt; ls = q; else a-&gt; rs = q; } p-&gt; pt = q; q-&gt; pt = a; if (q == p-&gt; ls) { if (q-&gt; rs) q-&gt; rs-&gt; pt = p; p-&gt; ls = q-&gt; rs; q-&gt; rs = p; } else { if (q-&gt; ls) q-&gt; ls-&gt; pt = p; p-&gt; rs = q-&gt; ls; q-&gt; ls = p; } p-&gt; update(); q-&gt; update(); }
void splay(splay_node* q) { static splay_node* stc[maxn]; int tst(1); stc[tst] = q; for (splay_node* p = q; p-&gt; pt; p = p-&gt; pt) stc[++ tst] = p-&gt; pt; for (; tst; &ndash; tst) stc[tst]-&gt; fix(); while (q-&gt; pt) { splay_node *p(q-&gt; pt); if (!p-&gt; pt || !p-&gt; pt-&gt; pt) rot(q); else { if ((q == p-&gt; ls) == (p == p-&gt; pt-&gt; ls)) { rot(p); rot(q); } else { rot(q); rot(q); } } } }
splay_node* expose(splay_node* p) { splay(p); while (p) { p-&gt; fix(); if (p-&gt; ls) p = p-&gt; ls; else break; } return p; }
void link(int e0, int u0, int v0) { splay_node *e(sr[e0]), *u(sr[u0]), *v(sr[v0]); splay(u); if (u-&gt; fix(), u-&gt; rs) u-&gt; rv ^= 1; splay(v); if (v-&gt; fix(), v-&gt; ls) v-&gt; rv ^= 1; e-&gt; rv = 0; e-&gt; ls = u; u-&gt; pt = e; e-&gt; rs = v; v-&gt; pt = e; e-&gt; update(); }
void cut(int e0) { splay_node* e(sr[e0]); splay(e); e-&gt; fix(); if (e-&gt; ls) { e-&gt; ls-&gt; pt = 0; e-&gt; ls = 0; } if (e-&gt; rs) { e-&gt; rs-&gt; pt = 0; e-&gt; rs = 0; } e-&gt; update(); }
int query(int u0, int v0) { splay_node *u(sr[u0]), *v(sr[v0]); if (expose(u) != expose(v)) return -1; if (u == v) return u-&gt; vl; int ans(max(u-&gt; vl, v-&gt; vl)); splay(u); splay(v); if (u == v-&gt; ls) { if (u-&gt; rs) upmax(ans, u-&gt; rs-&gt; vm); } else if (u == v-&gt; rs) { if (u-&gt; ls) upmax(ans, u-&gt; ls-&gt; vm); } return ans; }
int main() { scanf(&quot;%d%d%d%d&quot;, &amp;n, &amp;m, &amp;c, &amp;q); eb = n * c; for (int i = 1; i &lt;= eb + m; ++ i) sr[i] = slst + i; for (int i = 1; i &lt;= n; ++ i) { scanf(&quot;%d&quot;, v + i); for (int j = 0; j &lt; c; ++ j) { splay_node* p(sr[nid(i, j)]); p-&gt; vl = p-&gt; vm = v[i]; } } for (int i = 1; i &lt;= m; ++ i) { splay_node* p(sr[eid(i)]); p-&gt; vl = p-&gt; vm = 0; int u, v, w; scanf(&quot;%d%d%d&quot;, &amp;u, &amp;v, &amp;w); link(eid(i), nid(u, w), nid(v, w)); ce[i] = w; ++ nc[u][w]; ++ nc[v][w]; if (u &gt; v) swap(u, v); el. insert(mpr(edge(u, v), i)); } while (q &ndash;) { int opt, u, v, w; scanf(&quot;%d&quot;, &amp;opt); if (opt == 0) { scanf(&quot;%d%d&quot;, &amp;u, &amp;v); for (int i = 0; i &lt; c; ++ i) { splay_node* p(sr[nid(u, i)]); p-&gt; vl = v; p-&gt; update(); splay(p); } } else if (opt == 1) { scanf(&quot;%d%d%d&quot;, &amp;u, &amp;v, &amp;w); if (u &gt; v) swap(u, v); emap :: iterator it = el. find(edge(u, v)); if (it == el. end()) puts(&ldquo;No such edge.&rdquo;); else if (w == ce[it-&gt; second]) puts(&ldquo;Success.&rdquo;); else if (nc[u][w] &gt; 1 || nc[v][w] &gt; 1) puts(&ldquo;Error 1.&rdquo;); else if (expose(sr[nid(u, w)]) == expose(sr[nid(v, w)])) puts(&ldquo;Error 2.&rdquo;); else { int e(it-&gt; second); &ndash; nc[u][ce[e]]; &ndash; nc[v][ce[e]]; cut(eid(e)); ce[e] = w; ++ nc[u][ce[e]]; ++ nc[v][ce[e]]; link(eid(e), nid(u, w), nid(v, w)); puts(&ldquo;Success.&rdquo;); } } else { scanf(&quot;%d%d%d&quot;, &amp;w, &amp;u, &amp;v); printf(&quot;%d\n&quot;, query(nid(u, w), nid(v, w))); } } }

