int n, k, l, f[2][maxb], zu, va;
#define incm(a,b) { a += b; if (a &gt;= mod) a %= mod; }
int sov() { int prv(0), cur(1); memset(f, 0, sizeof(f)); va = max(0, l - k) + 1; zu = pow2(k + 1) - 1; f[cur][1] = 1; for (int ti = 0; ti &lt; n; ++ ti) { swap(cur, prv); for (int i = zu; i; &ndash; i) f[cur][i] = 0; for (int i = zu; i; &ndash; i) if (f[prv][i]) { for (int j = 1; j &lt;= k; ++ j) { int zn((i | (i &lt;&lt; j)) &amp; zu); incm(f[cur][zn], f[prv][i]); } incm(f[cur][i], _l f[prv][i] * va % mod); } } int ans(0); for (int i = zu, e = pow2(k); i &gt;= e; &ndash; i) incm(ans, f[cur][i]); return ans; }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
