	&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 灭绝树的模板题么。之前不知道这题，差点当原创题出出去了。&lt;/p&gt; &nbsp;
好像有不少人不知道这东西的样子？orz zhx。
&nbsp;
灭绝树只有一句口诀：一个东西的父亲是所有入边的另一端的点的LCA。
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
struct edge { int t; edge *next; };
const int maxn = 70009; const int maxl = 19; const int maxe = 2000009;
int n, ind[maxn], oud[maxn], tpo[maxn], ath[maxn][maxl], sz[maxn], d[maxn]; edge *ha[maxn], *hr[maxn], *ht[maxn];
inline void addEdge(edge** head, int u, int v) { edge* ep = new edge; ep-&gt; t = v; ep-&gt; next = head[u]; head[u] = ep; }
int LCA(int u, int v) { if (d[u] &lt; d[v]) swap(u, v); for (int i = maxl - 1; i &gt;= 0; &ndash; i) if (d[ath[u][i]] &gt;= d[v]) u = ath[u][i]; if (u == v) return u; for (int i = maxl - 1; i &gt;= 0; &ndash; i) if (ath[u][i] ^ ath[v][i]) { u = ath[u][i]; v = ath[v][i]; } return ath[u][0]; }
void topSort() { static int q[maxn]; int hd(0), tl(0); for (int i = 1; i &lt;= n; ++ i) if (!ind[i]) tpo[tl ++] = i; while (hd &lt; tl) { int p(tpo[hd ++]); for (edge* e = ha[p]; e; e = e-&gt; next) { &ndash; ind[e-&gt; t]; if (!ind[e-&gt; t]) tpo[tl ++] = e-&gt; t; } } d[0] = 0; for (int ti = 0; ti &lt; n; ++ ti) { int p(tpo[ti]), a; if (!hr[p]) { a = 0; } else { a = hr[p]-&gt; t; for (edge* e = hr[p]-&gt; next; e; e = e-&gt; next) a = LCA(a, e-&gt; t); } addEdge(ht, a, p); ath[p][0] = a; for (int i = 1; i &lt; maxl; ++ i) ath[p][i] = ath[ath[p][i - 1]][i - 1]; d[p] = d[a] + 1; } for (int ti = n - 1; ti &gt;= 0; &ndash; ti) { int p(tpo[ti]); sz[p] = 1; for (edge* e = ht[p]; e; e = e-&gt; next) sz[p] += sz[e-&gt; t]; } }
int main() { #ifndef ONLINE_JUDGE freopen(&ldquo;in.txt&rdquo;, &ldquo;r&rdquo;, stdin); #endif
scanf(&quot;%d&quot;, &amp;amp;n); for (int i = 1; i &amp;lt;= n; ++ i) { int v; while (scanf(&quot;%d&quot;, &amp;amp;v), v) { addEdge(ha, v, i); addEdge(hr, i, v); ++ oud[v]; ++ ind[i]; } } topSort(); for (int i = 1; i &amp;lt;= n; ++ i) printf(&quot;%d\n&quot;, sz[i] - 1); }

