static int q[maxn]; int hd(0), tl(1); q[0] = f[0] = 0; for (int i = 1; i &amp;lt;= n; ++ i) { while (hd &amp;lt; tl &amp;amp;&amp;amp; i &amp;gt;= q[hd] + k[q[hd]]) ++ hd; if (hd == tl) { f[i] = -1; continue; } f[i] = f[q[hd]] + 1; while (hd &amp;lt; tl &amp;amp;&amp;amp; (f[i] &amp;lt; f[q[tl - 1]] || (f[i] == f[q[tl - 1]] &amp;amp;&amp;amp; i + k[i] &amp;gt;= q[tl - 1] + k[q[tl - 1]]))) -- tl; q[tl ++] = i; } }
