&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; _a_%=mod;&nbsp;\
&nbsp;&nbsp;&nbsp; if (_a_&lt;0)&nbsp;\
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; _a_+=mod;&nbsp;\
}
&nbsp;
void pre(int n)&nbsp;{
&nbsp;&nbsp;&nbsp; memset(pr, 0, sizeof(pr));
&nbsp;&nbsp;&nbsp; tp = 0;
&nbsp;&nbsp;&nbsp; d[0]&nbsp;= 0;
&nbsp;&nbsp;&nbsp; d[1]&nbsp;= 1;
&nbsp;&nbsp;&nbsp; for (int i = 2; i &lt;= n;&nbsp;++ i)&nbsp;{
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; if (!pr[i])&nbsp;{
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; pn[tp ++]&nbsp;= i;&nbsp;&nbsp;&nbsp;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; d[i]&nbsp;=&nbsp;(i - _l i * i)&nbsp;% mod;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; if (d[i]&nbsp;&lt; 0)
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; d[i]&nbsp;+= mod;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; for (int j = 0; j &lt; tp &amp;&amp; i * pn[j]&nbsp;&lt;= n;&nbsp;++ j)&nbsp;{
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; pr[i * pn[j]]&nbsp;= 1;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; if (i&nbsp;% pn[j])&nbsp;{
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; d[i * pn[j]]&nbsp;= _l d[i]&nbsp;* d[pn[j]]&nbsp;% mod;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; else {
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; d[i * pn[j]]&nbsp;= _l d[i]&nbsp;* pn[j]&nbsp;% mod;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; break;
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp;&nbsp; for (int i = 2; i &lt;= n;&nbsp;++ i)
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; incm(d[i], d[i - 1]);
}
&nbsp;
inline int sumr(const int&amp; x)&nbsp;{
&nbsp;&nbsp;&nbsp; return (((_l x + 1)&nbsp;* x)&nbsp;&gt;&gt; 1)&nbsp;% mod;
}
&nbsp;
int sov(int m, int n)&nbsp;{
&nbsp;&nbsp;&nbsp; int ans(0);
&nbsp;&nbsp;&nbsp; for (int i = 1, j; i &lt;= n; i = j + 1)&nbsp;{
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; j = min(m /&nbsp;(m&nbsp;/ i), n /&nbsp;(n&nbsp;/ i));
&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; incm(ans,&nbsp;(_l d[j]&nbsp;- d[i - 1])&nbsp;* sumr(m / i)&nbsp;% mod * sumr(n / i)&nbsp;% mod);
&nbsp;&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp;&nbsp; return ans;
}
&nbsp;
