typedef pair &lt;double, int&gt; dpr;
struct edge {
int v, t;
edge *next;
};
#define nid(_x_,_y_)&nbsp;((_x_-1)*m+(_y_))
const int maxn = 10009;
const int maxa = 109;
const int maxe = 80009;
const int mov[4][2]&nbsp;=&nbsp;{{1, 0},&nbsp;{-1, 0},&nbsp;{0, 1},&nbsp;{0,&nbsp;-1}};
const double eps = 1e-8;
int n, m, st, te, c[maxn];
char mp[maxa][maxa];
double d[maxn], tg;
edge *head[maxn],&nbsp;*ep, elst[maxe];
dpr hp[maxe];
inline void addEdge(int u, int v, int w)&nbsp;{
ep-&gt; t = v;
ep-&gt; v = w;
ep-&gt; next = head[u];
head[u]&nbsp;= ep ++;
}
double dijkstra(double d0)&nbsp;{
int th(1);
hp[0]&nbsp;= dpr(0, st);
d[st]&nbsp;= 0;
memset(c, 0, sizeof(c));
while (th)&nbsp;{
dpr g(hp[0]);
pop_heap(hp, hp +&nbsp;(th&nbsp;--));
if (c[g. second]&nbsp;== 2)
continue;
c[g. second]&nbsp;= 2;
for (edge* e = head[g. second]; e; e = e-&gt; next)
if (c[e-&gt; t]&nbsp;&lt; 2)&nbsp;{
double v0(g. first -&nbsp;(e-&gt; v ? 1.0 : d0));
if (c[e-&gt; t]&nbsp;== 0 || v0 &gt; d[e-&gt; t])&nbsp;{
d[e-&gt; t]&nbsp;= v0;
c[e-&gt; t]&nbsp;= 1;
hp[th]&nbsp;= dpr(v0, e-&gt; t);
push_heap(hp, hp +&nbsp;(++ th));
}
}
}
return -d[te];
}
double sov()&nbsp;{
scanf(&quot;%lf%d%d&quot;,&nbsp;&amp;tg,&nbsp;&amp;n,&nbsp;&amp;m);
while (getchar()&nbsp;!= 10);
for (int i = 1; i &lt;= n;&nbsp;++ i)&nbsp;{
fgets(mp[i]&nbsp;+ 1, sizeof(char)&nbsp;* maxa, stdin);
for (int j = 1; j &lt;= m;&nbsp;++ j)&nbsp;{
int d(mp[i][j]);
