if (mp[i][j]&nbsp;== 32)
for (int mi = 0; mi &lt; 4;&nbsp;++ mi)&nbsp;{
int x(i + mov[mi][0]), y(j + mov[mi][1]);
if (x&nbsp;&gt; 0 &amp;&amp; x &lt;= n &amp;&amp; y &gt; 0 &amp;&amp; y &lt;= m &amp;&amp; mp[x][y]&nbsp;== 32)
addEdge(nid(i, j), nid(x, y),&nbsp;(mi &amp; 2));
}
double l(0), r(10.0);
while (l&nbsp;+ eps &lt; r)&nbsp;{
double mid((l + r)&nbsp;/ 2.0);
if (dijkstra(mid)&nbsp;&lt; tg)
l = mid + eps;
else
r = mid;
}
return l;
}
