c[i]&nbsp;= 1;
}
for (int j = 0, v; j &lt; tp &amp;&amp; i * pn[j]&nbsp;&lt;= n;&nbsp;++ j)&nbsp;{
v = i * pn[j];
pr[v]&nbsp;= 1;
if (i&nbsp;% pn[j])&nbsp;{
sa[v]&nbsp;= sa[i]&nbsp;* 2;
sb[v]&nbsp;= _l sb[i]&nbsp;*&nbsp;((_l pn[j]&nbsp;* pn[j]&nbsp;+ 1)&nbsp;% mod)&nbsp;% mod;
b[v]&nbsp;= i;
c[v]&nbsp;= 1;
}
else {
sa[v]&nbsp;= sa[i]&nbsp;/&nbsp;(c[i]&nbsp;+ 1)&nbsp;*&nbsp;(c[i]&nbsp;+ 2);
//int vn = v / b[i];
