struct splay_node {
&nbsp;&nbsp; int v, sz;
&nbsp;&nbsp; dint s;
&nbsp;&nbsp; splay_node *ls,&nbsp;*rs,&nbsp;*pt;
&nbsp;&nbsp; inline void init(int v0)&nbsp;{
&nbsp;&nbsp; v = v0;
&nbsp;&nbsp; sz = 1;
&nbsp;&nbsp; s = v0;
&nbsp;&nbsp; pt = ls = rs = 0;
&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp; inline void update()&nbsp;{
&nbsp;&nbsp; s = v;
&nbsp;&nbsp; sz = 1;
&nbsp;&nbsp; if (ls)&nbsp;{
&nbsp;&nbsp; s += ls-&gt; s;
&nbsp;&nbsp; sz += ls-&gt; sz;
&nbsp;&nbsp;&nbsp;}
&nbsp;&nbsp; if (rs)&nbsp;{
&nbsp;&nbsp; s += rs-&gt; s;
