p-&gt; ls = q-&gt; rs;
q-&gt; rs = p;
}
else {
if (q-&gt; ls)
q-&gt; ls-&gt; pt = p;
p-&gt; rs = q-&gt; ls;
q-&gt; ls = p;
}
p-&gt; update();
q-&gt; update();
}
void splay(splay_node* q)&nbsp;{
while (q-&gt; pt)&nbsp;{
splay_node *p&nbsp;= q-&gt; pt;
if (!p-&gt; pt)
rot(q);
else if ((p&nbsp;== p-&gt; pt-&gt; ls)&nbsp;==&nbsp;(q == p-&gt; ls))
rot(p), rot(q);
else
rot(q), rot(q);
}
cr = q;
}
splay_node* kth(splay_node* p, int k)&nbsp;{
while (p)
if (nsz(p-&gt; ls)&nbsp;+ 1 == k)
break;
else if (nsz(p-&gt; ls)&nbsp;&gt;= k)
p = p-&gt; ls;
else
