p-&gt; d = ptMerge(p-&gt; d, x);
}
else {
if (p-&gt; d)
pushDown(p);
if (r&nbsp;&lt;= mid(p))
sgtChg(p-&gt; ls, l, r, x);
else if (l&nbsp;&gt;= mid(p))
sgtChg(p-&gt; rs, l, r, x);
else {
sgtChg(p-&gt; ls, l, mid(p), x);
sgtChg(p-&gt; rs, mid(p), r, x);
}
}
}
oper sgtQry(seg* p, int p0)&nbsp;{
oper s(1, 0);
while (p-&gt; l + 1 &lt; p-&gt; r)&nbsp;{
s = moper(ptQry(p-&gt; d), s);
