}
const int maxn = 509;
const int maxq = 310009;
int n, m, t, maxa, a[maxn][maxn], b[maxn][maxn], ttm;
int d[maxn * maxn], ans[maxq], tdr[maxq];
query q[maxq];
void btChg(int x, int y, int v)&nbsp;{
for (int p = x; p &lt;= n; p +=&nbsp;(p&nbsp;&amp;&nbsp;-p))
for (int q = y; q &lt;= n; q +=&nbsp;(q&nbsp;&amp;&nbsp;-q))
if (b[p][q]&nbsp;^ ttm)&nbsp;{&nbsp;
a[p][q]&nbsp;= v;
b[p][q]&nbsp;= ttm;
}
else
a[p][q]&nbsp;+= v;
}
int btQry(int x, int y)&nbsp;{
int s = 0;
for (int p = x; p; p -=&nbsp;(p&nbsp;&amp;&nbsp;-p))
for (int q = y; q; q -=&nbsp;(q&nbsp;&amp;&nbsp;-q))
if (b[p][q]&nbsp;== ttm)
s += a[p][q];
return s;
}
void qSort(int vl, int vr, int ql, int qr)&nbsp;{
if (vl&nbsp;== vr)&nbsp;{
for (int i = ql; i &lt;= qr;&nbsp;++ i)
if (q[i]. n &gt;&nbsp;-1)
ans[q[i]. n]&nbsp;= d[vl];
}
else {
++ ttm;
int vm =&nbsp;(vl&nbsp;+ vr)&nbsp;&gt;&gt; 1;
for (int i = ql; i &lt;= qr;&nbsp;++ i)
if (q[i]. n ==&nbsp;-1)&nbsp;{
if (q[i]. k &lt;= d[vm])&nbsp;{
btChg(q[i]. x1, q[i]. y1, 1);
tdr[i]&nbsp;= 0;
}
else
tdr[i]&nbsp;= 1;
}
for (int i = ql; i &lt;= qr;&nbsp;++ i)
if (q[i]. n &gt;&nbsp;-1)&nbsp;{
int g = btQry(q[i]. x2, q[i]. y2)&nbsp;+ btQry(q[i]. x1, q[i]. y1)
&nbsp;&nbsp;&nbsp;- btQry(q[i]. x1, q[i]. y2)&nbsp;- btQry(q[i]. x2, q[i]. y1);
if (g&nbsp;&lt; q[i]. k)&nbsp;{
q[i]. k -= g;
tdr[i]&nbsp;= 1;
}
else
tdr[i]&nbsp;= 0;
}
int i = ql, j = qr;
while (i&nbsp;&lt; j)&nbsp;{
for (; i &lt; j &amp;&amp; tdr[i]&nbsp;== 0;&nbsp;++ i);
for (; i &lt; j &amp;&amp; tdr[j]&nbsp;== 1;&nbsp;-- j);
if (i&nbsp;&lt;= j)&nbsp;{
swap(q[i], q[j]);
swap(tdr[i], tdr[j]);
++ i;
-- j;
}
}
for (i&nbsp;= ql - 1; i &lt; qr &amp;&amp; tdr[i + 1]&nbsp;== 0;&nbsp;++ i);
if (ql&nbsp;&lt;= i)
qSort(vl, vm, ql, i);
if (i&nbsp;+ 1 &lt;= qr)
qSort(vm + 1, vr, i + 1, qr);
}
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
memset(a, 0, sizeof(a));
memset(b, 0, sizeof(b));
ttm = 0;
readInt(n);
readInt(m);
t = 0;
maxa = 0;
for (int i = 1; i &lt;= n;&nbsp;++ i)
for (int j = 1; j &lt;= n;&nbsp;++ j)&nbsp;{
readInt(q[t]. k);
if (q[t]. k &gt; maxa)
maxa = q[t]. k;
d[i * n + j - n - 1]&nbsp;= q[t]. k;
q[t]. x1 = i;
q[t]. y1 = j;
q[t]. n =&nbsp;-1;
++ t;
}
sort(d, d + n * n);
for (int i = 0; i &lt; m;&nbsp;++ i)&nbsp;{
readInt(q[t]. x1);
-- q[t]. x1;
readInt(q[t]. y1);
-- q[t]. y1;
readInt(q[t]. x2);
readInt(q[t]. y2);
readInt(q[t]. k);
q[t]. n = i;
++ t;
}
qSort(0, n * n - 1, 0, t - 1);
for (int i = 0; i &lt; m;&nbsp;++ i)
printf(&quot;%d\n&quot;, ans[i]);
}

