const int maxw = 2109;
const int inf = 0x3f3f3f3f;
int n, f[2][maxw][maxw], sw;
book a[maxn];
inline void upmin(int&amp; _a_, int _b_)&nbsp;{
if (_a_&nbsp;&gt; _b_)
_a_ = _b_;
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
scanf(&quot;%d&quot;,&nbsp;&amp;n);
sw = 0;
for (int i = 0; i &lt; n;&nbsp;++ i)&nbsp;{
scanf(&quot;%d%d&quot;,&nbsp;&amp;a[i]. h,&nbsp;&amp;a[i]. w);
sw += a[i]. w;
}
sort(a, a + n, cmpBook);
memset(f, 0x3f, sizeof(f));
int cur = 0, prv = 1;
f[cur][0][0]&nbsp;= a[0]. h;
for (int i = 1; i &lt; n;&nbsp;++ i)&nbsp;{
swap(cur, prv);
for (int j = 0; j &lt;= sw;&nbsp;++ j)
for (int k = 0; k &lt;= sw;&nbsp;++ k)
f[cur][j][k]&nbsp;= inf;
for (int j = 0; j &lt;= sw;&nbsp;++ j)
for (int k = 0; k &lt;= sw;&nbsp;++ k)
if (f[prv][j][k]&nbsp;&lt; inf)&nbsp;{
upmin(f[cur][j][k], f[prv][j][k]);
if (k)&nbsp;{
upmin(f[cur][j][k + a[i]. w], f[prv][j][k]);
if (j)
upmin(f[cur][j + a[i]. w][k], f[prv][j][k]);
else
upmin(f[cur][j + a[i]. w][k], f[prv][j][k]&nbsp;+ a[i]. h);
}
else
upmin(f[cur][j][k + a[i]. w], f[prv][j][k]&nbsp;+ a[i]. h);
}
}
int ans = inf;
for (int j = 1; j &lt;= sw;&nbsp;++ j)
for (int k = 1; k &lt;= sw;&nbsp;++ k)
if (sw&nbsp;- j - k &amp;&amp; f[cur][j][k]&nbsp;&lt; inf)
upmin(ans, f[cur][j][k]&nbsp;* max(max(j, k), sw - j - k));
printf(&quot;%d\n&quot;, ans);
}

