++ hd;
vy[i]&nbsp;= q[hd]&nbsp;-&nbsp;(i &lt;&lt; 1)&nbsp;+ 1;
if (i&nbsp;&amp;&amp; getLeft((i &lt;&lt; 1)&nbsp;-1)&nbsp;&lt; getLeft(q[tl - 1]))
