#else
#define lld &quot;%lld&quot;
#endif
struct edge {
int t;
edge *next;
};
struct splay_node {
int ls, rs, pt, sz, x;
qw v, a, s;
};
const int maxn = 200009;
int n, m, w[maxn];
int fa[maxn], dfb[maxn], dfe[maxn], dfo[maxn];
edge *ep,&nbsp;*head[maxn];
void dfsBuild()&nbsp;{
static int sa[maxn], sb[maxn];
int ta = 1, tb = 0, dfn = 0;
sa[ta]&nbsp;= 1;
memset(dfb, 0, sizeof(dfb));
while (ta)&nbsp;{
int p = sa[ta --];
while (tb&nbsp;&amp;&amp; sb[tb]&nbsp;!= fa[p])
dfe[sb[tb --]]&nbsp;=&nbsp;++ dfn;
sb[++ tb]&nbsp;= p;
dfb[p]&nbsp;=&nbsp;++ dfn;
for (edge* e = head[p]; e; e = e-&gt; next)
sa[++ ta]&nbsp;= e-&gt; t;
}
while (tb)
dfe[sb[tb --]]&nbsp;=&nbsp;++ dfn;
for (int i = 1; i &lt;= n;&nbsp;++ i)
dfo[dfb[i]]&nbsp;= i, dfo[dfe[i]]&nbsp;=&nbsp;-i;
}
#define lRot(_q_)&nbsp;{&nbsp;\
int _p_ = t[_q_]. pt, _a_ = t[_p_]. pt;&nbsp;\
if (_a_)&nbsp;{&nbsp;\
if (_p_&nbsp;== t[_a_]. ls)&nbsp;\
t[_a_]. ls = _q_;&nbsp;\
else \
t[_a_]. rs = _q_;&nbsp;\
}&nbsp;\
if (t[_q_]. rs)&nbsp;\
t[t[_q_]. rs]. pt = _p_;&nbsp;\
t[_p_]. ls = t[_q_]. rs;&nbsp;\
t[_q_]. rs = _p_;&nbsp;\
t[_q_]. pt = _a_;&nbsp;\
t[_p_]. pt = _q_;&nbsp;\
update(_p_);&nbsp;\
update(_q_);&nbsp;\
}
#define rRot(_q_)&nbsp;{&nbsp;\
int _p_ = t[_q_]. pt, _a_ = t[_p_]. pt;&nbsp;\
if (_a_)&nbsp;{&nbsp;\
if (_p_&nbsp;== t[_a_]. ls)&nbsp;\
t[_a_]. ls = _q_;&nbsp;\
else \
t[_a_]. rs = _q_;&nbsp;\
}&nbsp;\
if (t[_q_]. ls)&nbsp;\
t[t[_q_]. ls]. pt = _p_;&nbsp;\
t[_p_]. rs = t[_q_]. ls;&nbsp;\
t[_q_]. ls = _p_;&nbsp;\
t[_q_]. pt = _a_;&nbsp;\
t[_p_]. pt = _q_;&nbsp;\
update(_p_);&nbsp;\
update(_q_);&nbsp;\
}
#define update(_p_)&nbsp;{&nbsp;\
t[_p_]. sz = t[t[_p_]. ls]. sz + t[t[_p_]. rs]. sz + t[_p_]. x;&nbsp;\
t[_p_]. s = t[t[_p_]. ls]. s + t[t[_p_]. rs]. s + t[_p_]. v + t[_p_]. a * t[_p_]. sz;&nbsp;\
}
#define pushDown(_p_)&nbsp;{&nbsp;\
if (t[_p_]. a)&nbsp;{&nbsp;\
if (t[_p_]. ls)&nbsp;{&nbsp;\
t[t[_p_]. ls]. a += t[_p_]. a;&nbsp;\
update(t[_p_]. ls);&nbsp;\
}&nbsp;\
if (t[_p_]. rs)&nbsp;{&nbsp;\
t[t[_p_]. rs]. a += t[_p_]. a;&nbsp;\
update(t[_p_]. rs);&nbsp;\
}&nbsp;\
if (t[_p_]. x &gt; 0)&nbsp;\
t[_p_]. v += t[_p_]. a;&nbsp;\
else \
t[_p_]. v -= t[_p_]. a;&nbsp;\
t[_p_]. a = 0;&nbsp;\
}&nbsp;\
}
struct splay_tree {
splay_node t[maxn];
int cr, n;
splay_tree()&nbsp;{
t[0]. sz = 0;
t[0]. s = 0;
}
void dpath(int p)&nbsp;{
static int stc[maxn];
int tst = 1;
stc[1]&nbsp;= p;
for (; t[stc[tst]]. pt;&nbsp;++ tst)
stc[tst + 1]&nbsp;= t[stc[tst]]. pt;
for (; tst;&nbsp;-- tst)
pushDown(stc[tst]);
}
void splay(int q)&nbsp;{
dpath(q);
while (t[q]. pt)&nbsp;{
int p = t[q]. pt, a = t[p]. pt;
if (!a&nbsp;||&nbsp;!t[a]. pt)&nbsp;{
if (q&nbsp;== t[p]. ls)&nbsp;{
lRot(q);
}
else {
rRot(q);
}
}
else {
if (p&nbsp;== t[a]. ls)&nbsp;{
if (q&nbsp;== t[p]. ls)&nbsp;{
lRot(p);
lRot(q);
}
else {
rRot(q);
lRot(q);
}
}
else {
if (q&nbsp;== t[p]. rs)&nbsp;{
rRot(p);
rRot(q);
}
else {
lRot(q);
rRot(q);
}
}
}
}
cr = q;
}
inline int build(int l, int r, int pt = 0)&nbsp;{
if (l&nbsp;&gt;= r)
return 0;
int p =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
t[p]. pt = pt;
t[p]. v =&nbsp;((dfo[p]&nbsp;&gt; 0)&nbsp;? w[dfo[p]]&nbsp;:&nbsp;-w[-dfo[p]]);
t[p]. x =&nbsp;((dfo[p]&nbsp;&gt; 0)&nbsp;? 1 :&nbsp;-1);
t[p]. a = 0;
t[p]. ls = build(l, p, p);
t[p]. rs = build(p + 1, r, p);
update(p);
if (!pt)
cr = p, n = r;
return p;
}
int tmax(int p)&nbsp;{
while (t[p]. rs)
p = t[p]. rs;
return p;
}
int tmin(int p)&nbsp;{
while (t[p]. ls)
p = t[p]. ls;
return p;
}
int getRange(int l, int r)&nbsp;{
if (l&nbsp;== 1 &amp;&amp; r == n)
return cr;
else if (l&nbsp;== 1)&nbsp;{
splay(r);
int x = tmin(t[r]. rs);
splay(x);
return t[x]. ls;
}
else if (r&nbsp;== n)&nbsp;{
splay(l);
int x = tmax(t[l]. ls);
splay(x);
return t[x]. rs;
}
else {
splay(l);
int x = tmax(t[l]. ls);
splay(r);
int y = tmin(t[r]. rs);
splay(x);
splay(y);
return t[x]. rs;
}
}
inline qw getSum(int q)&nbsp;{
dpath(q);
return t[q]. s;
}
inline void add(int q, int v)&nbsp;{
t[q]. a += v;
update(q);
splay(q);
}
void cut(int q)&nbsp;{
int p = t[q]. pt;
dpath(q);
if (q&nbsp;== t[p]. ls)
t[p]. ls = 0;
else t[p]. rs = 0;
t[q]. pt = 0;
update(p);
splay(p);
}
void link(int q, int p)&nbsp;{
splay(p);
if (t[p]. rs)&nbsp;{
int x = tmin(t[p]. rs);
splay(x);
}
dpath(p);
t[p]. rs = q;
t[q]. pt = p;
update(p);
splay(q);
}
};
splay_tree t;
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
readInt(n);
memset(head, 0, sizeof(head));
ep = new edge[n];
for (int i = 2; i &lt;= n;&nbsp;++ i)&nbsp;{
readInt(fa[i]);
ep-&gt; t = i;
ep-&gt; next = head[fa[i]];
head[fa[i]]&nbsp;= ep ++;
}
for (int i = 1; i &lt;= n;&nbsp;++ i)
readInt(w[i]);
dfsBuild();
t. build(1, n * 2);
readInt(m);
while (m&nbsp;--)&nbsp;{
char opt;
int x, y;
readOpt(opt);
if (opt&nbsp;==&nbsp;'Q')&nbsp;{
readInt(x);
y = t. getRange(1, dfb[x]);
printf(lld &quot;\n&quot;, t. getSum(y));
}
else if (opt&nbsp;==&nbsp;'C')&nbsp;{
readInt(x);
readInt(y);
int a = t. getRange(dfb[x], dfe[x]);
t. cut(a);
t. link(a, dfb[y]);
