void splay(int q)&nbsp;{
dpath(q);
while (t[q]. pt)&nbsp;{
int p = t[q]. pt, a = t[p]. pt;
if (!a&nbsp;||&nbsp;!t[a]. pt)&nbsp;{
if (q&nbsp;== t[p]. ls)
lRot(q);
else
rRot(q);
}
else {
if (p&nbsp;== t[a]. ls)&nbsp;{
if (q&nbsp;== t[p]. ls)
lRot(p), lRot(q);
else
rRot(q), lRot(q);
}
else {
if (q&nbsp;== t[p]. ls)
lRot(q), rRot(q);
else
rRot(p), rRot(q);
}
}
}
cr = q;
}
int kth(int k)&nbsp;{
int p = cr;
while (p)
if (t[t[p]. ls]. sz == k)
break;
else if (t[t[p]. ls]. sz &gt; k)
p = t[p]. ls;
else
k -= t[t[p]. ls]. sz + 1, p = t[p]. rs;
return p;
}
int build(int l, int r)&nbsp;{
if (l&nbsp;&gt; r)
return 0;
int p =&nbsp;++ tn, mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
t[p]. val = 0;
t[p]. add = 0;
t[p]. mul = 1;
t[p]. ls = build(l, mid - 1);
if (t[p]. ls)
t[t[p]. ls]. pt = p;
t[p]. rs = build(mid + 1, r);
if (t[p]. rs)
t[t[p]. rs]. pt = p;
update(p);
return p;
}
int getRange(int l, int r)&nbsp;{
if (!cr)
cr = build(0, r);
if (r&nbsp;&gt;= t[cr]. sz)&nbsp;{
int x = kth(t[cr]. sz - 1);
int z = build(t[cr]. sz, r);
splay(x);
pushDown(x);
t[x]. rs = z;
t[z]. pt = x;
update(x);
}
if (!l&nbsp;&amp;&amp; r == t[cr]. sz - 1)
return cr;
else if (!l)&nbsp;{
int x = kth(r + 1);
splay(x);
return t[x]. ls;
}
else if (r&nbsp;== t[cr]. sz - 1)&nbsp;{
int x = kth(l - 1);
splay(x);
return t[x]. rs;
}
else {
int x = kth(l - 1);
int y = kth(r + 1);
splay(x);
splay(y);
return t[x]. rs;
}
}
void add(int p, int v)&nbsp;{
dpath(p);
t[p]. val =&nbsp;(_l t[p]. val + v)&nbsp;% mod;
t[p]. add =&nbsp;(_l t[p]. add + v)&nbsp;% mod;
}
void mul(int p, int v)&nbsp;{
dpath(p);
t[p]. val = _l t[p]. val * v % mod;
t[p]. add = _l t[p]. add * v % mod;
t[p]. mul = _l t[p]. mul * v % mod;
}
int rmvKth(int k)&nbsp;{
int x = getRange(k, k);
if (t[cr]. sz == 1)
return cr = 0, t[x]. val;
