int ret = t[x]. val;
if (t[x]. pt)&nbsp;{
if (x&nbsp;== t[t[x]. pt]. ls)
t[t[x]. pt]. ls = 0;&nbsp;
else
t[t[x]. pt]. rs = 0;&nbsp;
upath(t[x]. pt);
}
return ret;
}
void ins(int k)&nbsp;{
int x = getRange(k, k);
while (t[x]. ls)
x = t[x]. ls;
dpath(x);
++ tn;
t[tn]. ls = 0;
t[tn]. rs = 0;
t[tn]. pt = x;
t[tn]. sz = 1;
t[tn]. val = 0;
t[tn]. mul = 1;
t[tn]. add = 0;
t[x]. ls = tn;
