}
int dfsAns(int p, int&amp; x, int x0)&nbsp;{
int ret = 0;
pushDown(p);
if (t[p]. ls)
ret = dfsAns(t[p]. ls, x, x0);
ret =&nbsp;(_l ret + _l x * t[p]. val)&nbsp;% mod;
x = _l x * x0 % mod;
if (t[p]. rs)
ret =&nbsp;(ret&nbsp;+ dfsAns(t[p]. rs, x, x0))&nbsp;% mod;
return ret;
}
int getAns(int x)&nbsp;{
int tmp = 1;
return dfsAns(cr, tmp, x);
}
};
