写完Kdtree感觉整个人都要离散了。
这题比较神，之前连题都没看懂。每个位置的方案数就是上下左右的数量的组合数的乘积。把x离散之后维护区间中左&times;右的和，上下y相同的扫一遍搞定。（感觉说了像没说）
#include &lt;cstdio&gt;
#include &lt;cstring&gt;
#include &lt;algorithm&gt;
using namespace std;
struct point {
int x, y;
};
const int maxn = 100009;
const int maxk = 13;
inline bool cmpP(int* a, int* b)&nbsp;{
return *a&nbsp;&lt;&nbsp;*b;
}
inline bool cmpy(const point&amp; a, const point&amp; b)&nbsp;{
return (a. y &lt; b. y)&nbsp;||&nbsp;(a. y == b. y &amp;&amp; a. x &lt; b. x);
}
point a[maxn];
int n, m, c[maxn][maxk], cx[maxn], tx[maxn], t[maxn], maxx, ans;
int *r[maxn];
void prec()&nbsp;{
c[0][0]&nbsp;= 1;
for (int i = 0; i &lt;= n;&nbsp;++ i)
c[i][0]&nbsp;= 1;
for (int i = 1; i &lt;= m;&nbsp;++ i)&nbsp;{
for (int j = 0; j &lt; i;&nbsp;++ j)
c[j][i]&nbsp;= 0;
for (int j = i; j &lt;= n;&nbsp;++ j)
c[j][i]&nbsp;= c[j - 1][i]&nbsp;+ c[j - 1][i - 1];
}
}
void dispx()&nbsp;{
for (int i = 0; i &lt; n;&nbsp;++ i)
r[i]&nbsp;=&nbsp;&amp;a[i]. x;
sort(r, r + n, cmpP);
maxx = 0;
for (int i = 0, l =&nbsp;*r[0]&nbsp;- 1; i &lt; n;&nbsp;++ i)
if (*r[i]&nbsp;== l)
*r[i]&nbsp;= maxx;
else
l =&nbsp;*r[i],&nbsp;*r[i]&nbsp;=&nbsp;++ maxx;
memset(tx, 0, sizeof(tx));
for (int i = 0; i &lt; n;&nbsp;++ i)
++ tx[a[i]. x];
}
void btChg(int* t, int p, int v)&nbsp;{
for (; p &lt;= maxx; p +=&nbsp;(p&nbsp;&amp;&nbsp;-p))
t[p]&nbsp;+= v;
}
int btQry(int* t, int p)&nbsp;{
int s = 0;
for (; p; p -=&nbsp;(p&nbsp;&amp;&nbsp;-p))
s += t[p];
return s;
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
memset(t, 0, sizeof(t));
memset(cx, 0, sizeof(cx));
