for (int i = 0; i &lt; n;&nbsp;++ i)
scanf(&quot;%d%d&quot;,&nbsp;&amp;a[i]. x,&nbsp;&amp;a[i]. y);
scanf(&quot;%d&quot;,&nbsp;&amp;m);
prec();
dispx();
sort(a, a + n, cmpy);
ans = 0;
for (int i = 0, j; i &lt; n; i = j)&nbsp;{
for (j&nbsp;= i; j &lt; n &amp;&amp; a[j]. y == a[i]. y;&nbsp;++ j);
for (int k = i + m - 1; k + m &lt; j;&nbsp;++ k)
if (a[k]. x &lt; a[k + 1]. x)
ans +=&nbsp;(btQry(t, a[k + 1]. x - 1)&nbsp;- btQry(t, a[k]. x))&nbsp;
* c[k - i + 1][m]&nbsp;* c[j - k - 1][m];
for (int k = i; k &lt; j;&nbsp;++ k)&nbsp;{
int x = a[k]. x;
btChg(t, x,&nbsp;-c[cx[x]][m]&nbsp;* c[tx[x]&nbsp;- cx[x]][m]);
++ cx[x];
btChg(t, x, c[cx[x]][m]&nbsp;* c[tx[x]&nbsp;- cx[x]][m]);
}
}
printf(&quot;%d\n&quot;, ans &amp; 0x7fffffff);
}

