++ xe[a[i]];
for (int i = 0; i &lt;= maxv;&nbsp;++ i)&nbsp;{
xb[i]&nbsp;= tib;
tib += xe[i];
xe[i]&nbsp;= xb[i];
}
for (int i = 1; i &lt;= n;&nbsp;++ i)
