return f[a]&nbsp;* r[a]&nbsp;&lt; f[b]&nbsp;* r[b]&nbsp;||&nbsp;(f[a]&nbsp;* r[a]&nbsp;== f[b]&nbsp;* r[b]&nbsp;&amp;&amp; f[a]&nbsp;&lt; f[b]);
}
int getmax(int l, int r, double k)&nbsp;{
-- r;
if (l&nbsp;== r)
return h[l];
-- r;
if (k&nbsp;&lt; getk(h[r], h[r + 1]))
