}
void cdq(int l, int r, int&amp; tb, double&amp; ans)&nbsp;{
if (l&nbsp;+ 1 == r)&nbsp;{
double fn = 1.0 /&nbsp;(:: r[l]&nbsp;* a[l]&nbsp;+ b[l]);
if (fn&nbsp;&gt; f[l])
f[l]&nbsp;= fn;
h[(tb = r)&nbsp;- 1]&nbsp;= l;
