}
else {
int bl, br, mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
double sl, sr;
cdq(l, mid, bl, sl);
ans = sl;
for (int i = mid; i &lt; r;&nbsp;++ i)&nbsp;{
int j = getmax(l, bl,&nbsp;-a[i]&nbsp;/ b[i]);
double fn = max(sl, f[j]&nbsp;*&nbsp;(:: r[j]&nbsp;* a[i]&nbsp;+ b[i]))&nbsp;/&nbsp;(:: r[i]&nbsp;* a[i]&nbsp;+ b[i]);
if (fn&nbsp;&gt; f[i])&nbsp;{
f[i]&nbsp;= fn;
}
ans = max(ans, f[i]&nbsp;*&nbsp;(:: r[i]&nbsp;* a[i]&nbsp;+ b[i]));
}
cdq(mid, r, br, sr);
ans = max(ans, sr);
tb = l;
for (int i = l, j = mid; i &lt; bl || j &lt; br;)&nbsp;{
int k;
if (j&nbsp;== br ||&nbsp;(i&nbsp;&lt; bl &amp;&amp; getx(h[i])&nbsp;&lt; getx(h[j])))
k = h[i ++];
else
k = h[j ++];
