scanf(&quot;%d%d%d&quot;,&nbsp;&amp;a[i]. a,&nbsp;&amp;a[i]. b,&nbsp;&amp;a[i]. c);
sort(a, a + n, cmpFlower);
for (int i = 0, j; i &lt; n; i = j + 1)&nbsp;{
int s = 0;
for (int p = a[i]. b; p; p -=&nbsp;(p&nbsp;&amp;&nbsp;-p))
s += sbt :: cntLower(t[p], a[i]. c);
for (j&nbsp;= i; equFlower(a[i], a[j + 1])&nbsp;&amp;&amp; j &lt; n;&nbsp;++ j);
