for (int p = a[k]. b; p &lt;= m; p +=&nbsp;(p&nbsp;&amp;&nbsp;-p))
sbt :: ins(t[p], a[k]. c);
}
}
for (int i = 0; i &lt; n;&nbsp;++ i)
printf(&quot;%d\n&quot;, ans[i]);
}

