iq[p]&nbsp;= 1;
for (edge* e = head[p]; e; e = e-&gt; next)
if (d[e-&gt; t]&nbsp;-&nbsp;(d[p]&nbsp;+ e-&gt; v)&nbsp;&gt; eps)&nbsp;{
if (iq[e-&gt; t])
return 1;
else {
d[e-&gt; t]&nbsp;= d[p]&nbsp;+ e-&gt; v;
if (dfs(e-&gt; t))
