content:
数据结构题神马的最开心了。
乍一看动态树，其实不然。复杂度可以再乘一个log的。
启发式合并。然后合并的时候直接暴力重构整棵子树，建主席树只和父亲节点有关，所以还是能搞定。
写了一个机智的垃圾回收把log^2的空间变成了log。然后发现空间有512MB。
#include &lt;cstdio&gt;
#include &lt;cctype&gt;
#include &lt;cstring&gt;
#include &lt;algorithm&gt;
using namespace std;
struct edge {
int t;
edge* next;
};
struct seg {
int v, c;
seg *ls,&nbsp;*rs;
};
#define readInt(_s_)&nbsp;{\
int _d_;\
_s_ = 0;\
while (!isdigit(_d_&nbsp;= getchar()));\
while ((_s_&nbsp;= _s_ * 10 + _d_ - 48), isdigit(_d_ = getchar()));\
}
const int maxn = 80009;
const int maxl = 33;
const int maxnd = maxn * maxl;
int n, m, q, v[maxn], r[maxn], sz[maxn], tsst, maxv;
int vis[maxn], tvis;
int d[maxn], ath[maxn][maxl];
edge *head[maxn],&nbsp;*ep;
seg *rt[maxn],&nbsp;*slst[maxnd];
void init()&nbsp;{
ep = new edge[maxn * 2];
memset(head, 0, sizeof(head));
memset(rt, 0, sizeof(rt));
seg *sp&nbsp;= new seg[maxnd + 9];
for (int i = 0; i &lt; maxnd;&nbsp;++i)&nbsp;{
sp-&gt; ls = 0;
sp-&gt; rs = 0;
slst[i]&nbsp;= sp ++;
}
tsst = maxnd;
tvis = 0;
memset(vis, 0, sizeof(vis));
d[0]&nbsp;= 0;
for (int i = 0; i &lt; maxl;&nbsp;++ i)
ath[0][i]&nbsp;= 0;
}
inline seg* newSeg()&nbsp;{
seg* r = slst[-- tsst];
if (r-&gt; ls)
if (!(-- r-&gt; ls-&gt; c))
slst[tsst ++]&nbsp;= r-&gt; ls;
if (r-&gt; rs)
if (!(-- r-&gt; rs-&gt; c))
slst[tsst ++]&nbsp;= r-&gt; rs;
return r;
}
inline void addEdge(int u, int v)&nbsp;{
ep-&gt; t = v;
ep-&gt; next = head[u];
head[u]&nbsp;= ep ++;
}
#define vof(p)&nbsp;((p)?(p-&gt;v):0)
#define lson(p)&nbsp;((p)?(p-&gt;ls):0)
#define rson(p)&nbsp;((p)?(p-&gt;rs):0)
seg* sgtIns(seg* q, int p0)&nbsp;{
seg *s&nbsp;= newSeg(),&nbsp;*p = s;
int l = 0, r = maxv + 1;
while (l&nbsp;+ 1 &lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
p-&gt; v = vof(q)&nbsp;+ 1;
p-&gt; c = 1;
if (p0&nbsp;&lt; mid)&nbsp;{
p-&gt; rs = rson(q);
if (rson(q))
++ q-&gt; rs-&gt; c;
q = lson(q);
p-&gt; ls = newSeg();
p = p-&gt; ls;
r = mid;
}
else {
p-&gt; ls = lson(q);
if (lson(q))
++ q-&gt; ls-&gt; c;
q = rson(q);
p-&gt; rs = newSeg();
p = p-&gt; rs;
l = mid;
}
}
p-&gt; v = vof(q)&nbsp;+ 1;
p-&gt; c = 1;
p-&gt; ls = 0;
p-&gt; rs = 0;
return s;
}
int sgtKth(seg* a1, seg* a2, seg* b1, seg* b2, int k)&nbsp;{
int l = 0, r = maxv + 1;
while (l&nbsp;+ 1 &lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
int t = vof(lson(a1))&nbsp;+ vof(lson(a2))&nbsp;- vof(lson(b1))&nbsp;- vof(lson(b2));
if (t&nbsp;&gt;= k)&nbsp;{
r = mid;
a1 = lson(a1);
a2 = lson(a2);
b1 = lson(b1);
b2 = lson(b2);
}
else {
k -= t;
l = mid;
a1 = rson(a1);
a2 = rson(a2);
b1 = rson(b1);
b2 = rson(b2);
}
}
return l;
}
int getRoot(int x)&nbsp;{
static int stc[maxn];
int tst = 1;
stc[tst]&nbsp;= x;
while (stc[tst]&nbsp;^ r[stc[tst]])&nbsp;{
stc[tst + 1]&nbsp;= r[stc[tst]];
++ tst;
}
while (-- tst)
r[stc[tst]]&nbsp;= r[stc[tst + 1]];
return r[x];
}
void rebuild(int p0, int a)&nbsp;{
static int q[maxn];
int hd = 0, tl = 1;
vis[p0]&nbsp;=&nbsp;++ tvis;
ath[p0][0]&nbsp;= a;
d[p0]&nbsp;= d[a]&nbsp;+ 1;
q[0]&nbsp;= p0;
while (hd&nbsp;&lt; tl)&nbsp;{
int p = q[hd ++];
if (rt[p])
slst[tsst ++]&nbsp;= rt[p], rt[p]&nbsp;= 0;
for (int i = 1; i &lt; maxl;&nbsp;++ i)
ath[p][i]&nbsp;= ath[ath[p][i - 1]][i - 1];
for (edge* e = head[p]; e; e = e-&gt; next)
if (vis[e-&gt; t]&nbsp;&lt; tvis)&nbsp;{
vis[e-&gt; t]&nbsp;= tvis;
d[e-&gt; t]&nbsp;= d[p]&nbsp;+ 1;
ath[e-&gt; t][0]&nbsp;= p;
q[tl ++]&nbsp;= e-&gt; t;
}
}
for (int ti = 0; ti &lt; tl;&nbsp;++ ti)
rt[q[ti]]&nbsp;= sgtIns(rt[ath[q[ti]][0]], v[q[ti]]);
}
int LCA(int u, int v)&nbsp;{
if (d[u]&nbsp;&lt; d[v])
swap(u, v);
for (int i = maxl - 1; i &gt;= 0;&nbsp;-- i)
if (d[ath[u][i]]&nbsp;&gt;= d[v])
u = ath[u][i];
if (u&nbsp;== v)
return u;
for (int i = maxl - 1; i &gt;= 0;&nbsp;-- i)
if (ath[u][i]&nbsp;^ ath[v][i])&nbsp;{
u = ath[u][i];
v = ath[v][i];
}
return ath[u][0];
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
init();
readInt(maxv);
readInt(n);
readInt(m);
readInt(q);
maxv = 0;
for (int i = 1; i &lt;= n;&nbsp;++ i)&nbsp;{
readInt(v[i]);
maxv = max(maxv, v[i]);
}
for (int i = 1; i &lt;= n;&nbsp;++ i)
r[i]&nbsp;= i, sz[i]&nbsp;= 1;
for (int i = 0; i &lt; m;&nbsp;++ i)&nbsp;{
int u, v;
readInt(u);
readInt(v);
addEdge(u, v);
addEdge(v, u);
u = getRoot(u);
v = getRoot(v);
sz[v]&nbsp;+= sz[u];
r[u]&nbsp;= v;
}
for (int i = 1; i &lt;= n;&nbsp;++ i)
if (!rt[i])
rebuild(i, 0);
int lans = 0;
while (q&nbsp;--)&nbsp;{
char opt[2];
int u, v, k;
scanf(&quot;%s&quot;, opt);
readInt(u);
readInt(v);
u ^= lans;
v ^= lans;
if (opt[0]&nbsp;==&nbsp;'L')&nbsp;{
int ru = getRoot(u), rv = getRoot(v);
if (sz[ru]&nbsp;&lt; sz[rv])
swap(ru, rv), swap(u, v);
r[rv]&nbsp;= ru;
sz[ru]&nbsp;+= sz[rv];
rebuild(v, u);
addEdge(u, v);
addEdge(v, u);
}
else {
readInt(k);
k ^= lans;
int a = LCA(u, v);
printf(&quot;%d\n&quot;,&nbsp;(lans = sgtKth(rt[u], rt[v], rt[a], rt[ath[a][0]], k)));
}
}
}

