好恶心的数据结构题。
考虑单个询问。把(视作1，把)视作-1，设minprefix为最小前缀和，设cp=(minprefix+1)/2，那么答案为(sum/2+cp*2)，使劲想想想得出来。
所以就是用个splay或者smt来维护一下一段的最小前缀和以及总和。因为有两种操作所以写起来比较麻烦。要注意不要把操作看反了，还要注意标记的优先级和更新的问题。
恶心了一下午。
#include &lt;cstdio&gt;
#include &lt;cstring&gt;
#include &lt;algorithm&gt;
using namespace std;
struct dat {
int sm, t[2][2];
inline void operator =(const dat&amp; a)&nbsp;{
sm = a. sm;
t[0][0]&nbsp;= a. t[0][0];
t[0][1]&nbsp;= a. t[0][1];
t[1][0]&nbsp;= a. t[1][0];
t[1][1]&nbsp;= a. t[1][1];
}
};
const int maxn = 100009;
int n, m, cr, a[maxn], sz[maxn], ls[maxn], rs[maxn], pt[maxn], vl[maxn];
bool flip[maxn], rev[maxn];
dat d[maxn];
dat sgd(int v)&nbsp;{
dat r;
r. sm = v;
r. t[0][0]&nbsp;= min(v, 0);
r. t[1][0]&nbsp;= r. t[0][0];
r. t[0][1]&nbsp;= min(-v, 0);
r. t[1][1]&nbsp;= r. t[0][1];
return r;
}
dat mgd(const dat&amp; a, const dat&amp; b)&nbsp;{
dat r;
r. sm = a. sm + b. sm;
r. t[0][0]&nbsp;= min(a. t[0][0], a. sm + b. t[0][0]);
r. t[1][0]&nbsp;= min(b. t[1][0], b. sm + a. t[1][0]);
r. t[0][1]&nbsp;= min(a. t[0][1],&nbsp;-a. sm + b. t[0][1]);
r. t[1][1]&nbsp;= min(b. t[1][1],&nbsp;-b. sm + a. t[1][1]);
return r;
}
inline void fix(int p)&nbsp;{
if (flip[p])&nbsp;{
swap(ls[p], rs[p]);
swap(d[p]. t[0][0], d[p]. t[1][0]);
swap(d[p]. t[0][1], d[p]. t[1][1]);
if (ls[p])
flip[ls[p]]&nbsp;^= 1;
if (rs[p])
flip[rs[p]]&nbsp;^= 1;
flip[p]&nbsp;= 0;
}
}
inline void reverse(dat&amp; r)&nbsp;{
swap(r. t[0][0], r. t[0][1]);
swap(r. t[1][0], r. t[1][1]);
r. sm =&nbsp;-r. sm;
}
inline void pushDown(int p)&nbsp;{
if (rev[p])&nbsp;{
if (ls[p])&nbsp;{
rev[ls[p]]&nbsp;^= 1;
reverse(d[ls[p]]);
}
if (rs[p])&nbsp;{
rev[rs[p]]&nbsp;^= 1;
reverse(d[rs[p]]);
}
vl[p]&nbsp;=&nbsp;-vl[p];
rev[p]&nbsp;= 0;
}
}
inline void update(int p)&nbsp;{
sz[p]&nbsp;= sz[ls[p]]&nbsp;+ sz[rs[p]]&nbsp;+ 1;
d[p]&nbsp;= sgd(rev[p]&nbsp;?&nbsp;-vl[p]&nbsp;: vl[p]);
if (ls[p])&nbsp;{
fix(ls[p]);
d[p]&nbsp;= mgd(d[ls[p]], d[p]);
}
if (rs[p])&nbsp;{
fix(rs[p]);
d[p]&nbsp;= mgd(d[p], d[rs[p]]);
}
if (rev[p])
reverse(d[p]);
}
inline void lRot(int q)&nbsp;{
int p = pt[q], a = pt[p];
if (rs[q])
pt[rs[q]]&nbsp;= p;
ls[p]&nbsp;= rs[q];
rs[q]&nbsp;= p;
pt[q]&nbsp;= a;
pt[p]&nbsp;= q;
if (a)&nbsp;{
if (p&nbsp;== ls[a])
ls[a]&nbsp;= q;
else
rs[a]&nbsp;= q;
}
update(p);
update(q);
}
inline void rRot(int q)&nbsp;{
int p = pt[q], a = pt[p];
if (ls[q])
pt[ls[q]]&nbsp;= p;
rs[p]&nbsp;= ls[q];
ls[q]&nbsp;= p;
pt[q]&nbsp;= a;
pt[p]&nbsp;= q;
if (a)&nbsp;{
if (p&nbsp;== ls[a])
ls[a]&nbsp;= q;
else
rs[a]&nbsp;= q;
}
update(p);
update(q);
}
void splay(int q)&nbsp;{
static int stc[maxn];
int tst = 1;
stc[tst]&nbsp;= q;
while (pt[stc[tst]])&nbsp;{
stc[tst + 1]&nbsp;= pt[stc[tst]];
++ tst;
}
while (tst)&nbsp;{
fix(stc[tst]);
pushDown(stc[tst]);
-- tst;
}
while (pt[q])&nbsp;{
int p = pt[q], a = pt[p];
if (!a&nbsp;||&nbsp;!pt[a])&nbsp;{
if (q&nbsp;== ls[p])
lRot(q);
else
rRot(q);
}
else {
if (p&nbsp;== ls[a])&nbsp;{
if (q&nbsp;== ls[p])
lRot(p), lRot(q);
else
rRot(q), lRot(q);
}
else {
if (q&nbsp;== ls[p])
lRot(q), rRot(q);
else
rRot(p), rRot(q);
}
}
}
cr = q;
}
int buildTree(int l, int r)&nbsp;{
if (l&nbsp;&gt; r)
return 0;
int p =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
ls[p]&nbsp;= buildTree(l, p - 1);
if (ls[p])
pt[ls[p]]&nbsp;= p;
rs[p]&nbsp;= buildTree(p + 1, r);
if (rs[p])
pt[rs[p]]&nbsp;= p;
sz[p]&nbsp;= sz[ls[p]]&nbsp;+ sz[rs[p]]&nbsp;+ 1;
rev[p]&nbsp;= 0;
flip[p]&nbsp;= 0;
vl[p]&nbsp;= a[p];
update(p);
return p;
}
int kth(int p, int k)&nbsp;{
while (p)&nbsp;{
fix(p);
if (sz[ls[p]]&nbsp;+ 1 == k)
break;
else if (sz[ls[p]]&nbsp;+ 1 &gt; k)
p = ls[p];
else
k -= sz[ls[p]]&nbsp;+ 1, p = rs[p];
}
return p;
}
int getRange(int l, int r)&nbsp;{
if (l&nbsp;== 1 &amp;&amp; r == n)
return cr;
else if (l&nbsp;== 1)&nbsp;{
int p = kth(cr, r + 1);
splay(p);
return ls[p];
}
else if (r&nbsp;== n)&nbsp;{
int p = kth(cr, l - 1);
splay(p);
return rs[p];
}
else {
int p = kth(cr, l - 1), q = kth(cr, r + 1);
splay(p);
splay(q);
return rs[p];
}
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
memset(flip, 0, sizeof(flip));
memset(rev, 0, sizeof(rev));
scanf(&quot;%d%d&quot;,&nbsp;&amp;n,&nbsp;&amp;m);
for (int i = 1; i &lt;= n;&nbsp;++ i)&nbsp;{
int g;
do
g = getchar();
while (g&nbsp;!=&nbsp;'('&nbsp;&amp;&amp; g !=&nbsp;')');
a[i]&nbsp;=&nbsp;(g ==&nbsp;'(')&nbsp;? 1 :&nbsp;-1;
}
cr = buildTree(1, n);
while (m&nbsp;--)&nbsp;{
int opt, l, r;
scanf(&quot;%d%d%d&quot;,&nbsp;&amp;opt,&nbsp;&amp;l,&nbsp;&amp;r);
if (opt&nbsp;== 0)&nbsp;{
int x = getRange(l, r);
fix(x);
pushDown(x);
update(x);
printf(&quot;%d\n&quot;,&nbsp;(d[x]. sm &gt;&gt; 1)&nbsp;+&nbsp;((-d[x]. t[0][0]&nbsp;+ 1)&nbsp;&amp;&nbsp;~1));
}
else if (opt&nbsp;== 2)&nbsp;{
int x = getRange(l, r);
flip[x]&nbsp;^= 1;
splay(x);
}
else if (opt&nbsp;== 1)&nbsp;{
int x = getRange(l, r);
rev[x]&nbsp;^= 1;
reverse(d[x]);
splay(x);
}
}
}

