好厉害的数据结构题，时限太吓人了。
最初想写莫队的，但是在数据范围下屈服了。
用可持久化线段树套可持久化线段树来维护可过。虽然跑了97s。本机跑得快得多，虽然有两个点被卡到了18s。
#include &lt;cstdio&gt;
#include &lt;cctype&gt;
#include &lt;cstring&gt;
#include &lt;algorithm&gt;
using namespace std;
struct seg {
int v, ls, rs;
};
#define readInt(_s_)&nbsp;{\
_s_ = 0;\
int _d_ = 0;\
while (!isdigit(_d_&nbsp;= getchar()));\
while ((_s_&nbsp;= _s_ * 10 + _d_ - 48), isdigit(_d_ = getchar()));\
}
const int maxn = 100009;
const int maxl = 20;
const int maxnd = maxn * maxl * maxl;
seg s[maxnd];
int n, m, t, a[maxn], d[maxn], c[maxn],&nbsp;*r[maxn], sp, rt[maxn];
inline bool cmpP(int* a, int* b)&nbsp;{
return *a&nbsp;&lt;&nbsp;*b;
}
#define vof(p)&nbsp;((p)?(s[p].v):0)
#define lson(p)&nbsp;((p)?(s[p].ls):0)
#define rson(p)&nbsp;((p)?(s[p].rs):0)
int sgtIns(int q, int p0)&nbsp;{
int rt =&nbsp;++ sp, p = rt;
int l = 0, r = n;
while (l&nbsp;&lt; r)&nbsp;{
s[p]. v = vof(q)&nbsp;+ 1;
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (p0&nbsp;&lt;= mid)&nbsp;{
s[p]. rs = rson(q);
q = lson(q);
s[p]. ls =&nbsp;++ sp;
p = s[p]. ls;
r = mid;
}
else {
s[p]. ls = lson(q);
q = rson(q);
s[p]. rs =&nbsp;++ sp;
p = s[p]. rs;
l = mid + 1;
}
}
s[p]. v = vof(q)&nbsp;+ 1;
return rt;
}
int psgtIns(int q, int p0, int v0)&nbsp;{
int rt =&nbsp;++ sp, p = rt;
int l = 1, r = t;
while (l&nbsp;&lt; r)&nbsp;{
s[p]. v = sgtIns(vof(q), v0);
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (p0&nbsp;&lt;= mid)&nbsp;{
s[p]. rs = rson(q);
q = lson(q);
s[p]. ls =&nbsp;++ sp;&nbsp;
p = s[p]. ls;
r = mid;
}
else {
s[p]. ls = lson(q);
q = rson(q);
s[p]. rs =&nbsp;++ sp;
p = s[p]. rs;
l = mid + 1;
}
}
s[p]. v = sgtIns(vof(q), v0);
return rt;
}
void dispNums()&nbsp;{
for (int i = 1; i &lt;= n;&nbsp;++ i)
r[i - 1]&nbsp;= a + i;
sort(r, r + n, cmpP);
t = 0;
for (int i = 0, l =&nbsp;*r[0]&nbsp;- 1; i &lt; n;&nbsp;++ i)
if (*r[i]&nbsp;== l)
*r[i]&nbsp;= t;
else {
d[++ t]&nbsp;=&nbsp;*r[i];
&nbsp;&nbsp; l =&nbsp;*r[i];
*r[i]&nbsp;= t;
}
d[++ t]&nbsp;=&nbsp;*r[n - 1]&nbsp;+ 1;
memset(c, 0, sizeof(c));
rt[0]&nbsp;= 0;
sp = 0;
for (int i = 1; i &lt;= n;&nbsp;++ i)&nbsp;{
rt[i]&nbsp;= psgtIns(rt[i - 1], a[i], c[a[i]]);
c[a[i]]&nbsp;= i;
}
}
int sgtQry(int p, int p0)&nbsp;{
int ans = 0;
int l = 0, r = n;
while (l&nbsp;&lt; r &amp;&amp; p)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (p0&nbsp;&lt;= mid)&nbsp;{
r = mid;
p = lson(p);
}
else {
l = mid + 1;
ans += vof(lson(p));
p = rson(p);
}
}
if (p)
ans += vof(p);
return ans;
}
void psgtQry(int p, int p0, int v0, int&amp; x, int&amp; y)&nbsp;{
x = 0;
y = 0;
if (p0&nbsp;== 0)
return;
int l = 1, r = t;
while (l&nbsp;&lt; r &amp;&amp; p)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (p0&nbsp;&lt;= mid)&nbsp;{
r = mid;
p = lson(p);
}
else {
x += vof(vof(lson(p)));
y += sgtQry(vof(lson(p)), v0);
l = mid + 1;
p = rson(p);
}
}
if (p)&nbsp;{
x += vof(vof(p));
y += sgtQry(vof(p), v0);
}
}
void query(int l, int r, int a, int b)&nbsp;{
int tt = 0, ct = 0, x, y;
psgtQry(rt[r], b, l - 1, x, y);
tt += x;
ct += y;
psgtQry(rt[r], a - 1, l - 1, x, y);
tt -= x;
ct -= y;
psgtQry(rt[l - 1], b, l - 1, x, y);
tt -= x;
ct -= y;
psgtQry(rt[l - 1], a - 1, l - 1, x, y);
tt += x;
ct += y;
printf(&quot;%d %d\n&quot;, tt, ct);
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
readInt(n);
readInt(m);
for (int i = 1; i &lt;= n;&nbsp;++ i)
readInt(a[i]);
dispNums();
while (m&nbsp;--)&nbsp;{
int l, r, a, b;
readInt(l);
readInt(r);
readInt(a);
readInt(b);
a = lower_bound(d, d + t, a)&nbsp;- d;&nbsp;
b = upper_bound(d, d + t, b)&nbsp;- d - 1;
if (a&nbsp;&gt; b)
puts(&quot;0 0&quot;);
else
query(l, r, a, b);
}
}

