前天晚上的best coder的题。
数据太弱暴力都放过去了，而且还是错的。当然我也太naive了TT。
我没管k&lt;=10，直接硬上树状数组套平衡树，用二分搞的。然后数组开小了不开心啊。
#include &lt;cstdio&gt;
#include &lt;cmath&gt;
#include &lt;cctype&gt;
#include &lt;algorithm&gt;
#include &lt;set&gt;
#include &lt;memory.h&gt;
using namespace std;
struct query {
int x, y, k, n;
};
struct tower {
int x, y, h;
};
inline bool cmpTower(const tower&amp; a, const tower&amp; b)&nbsp;{
return a. x &lt; b. x;
}
inline bool cmpQuery(const query&amp; a, const query&amp; b)&nbsp;{
return a. x &lt; b. x;
}
inline bool cmpP(int* a, int* b)&nbsp;{
return *a&nbsp;&lt;&nbsp;*b;
}
const int maxn = 30009;
const int maxl = 19;
const int maxv = 1e9 + 9;
int n, m,&nbsp;*rx[maxn * 2],&nbsp;*ry[maxn * 2], mx, my;
int ans[maxn];
tower a[maxn];
query q[maxn];
int t[maxn * 2];
namespace sbt {
const int maxnd = maxn * maxl;
int sz[maxnd], ls[maxnd], rs[maxnd], vl[maxnd], tn;
void init()&nbsp;{
tn = 0;
sz[0]&nbsp;= 0;
}
inline void lRot(int&amp; p)&nbsp;{
int q = rs[p];
rs[p]&nbsp;= ls[q];
ls[q]&nbsp;= p;
sz[q]&nbsp;= sz[p];
sz[p]&nbsp;= sz[ls[p]]&nbsp;+ sz[rs[p]]&nbsp;+ 1;
p = q;
}
inline void rRot(int&amp; p)&nbsp;{
int q = ls[p];
ls[p]&nbsp;= rs[q];
rs[q]&nbsp;= p;
sz[q]&nbsp;= sz[p];
sz[p]&nbsp;= sz[ls[p]]&nbsp;+ sz[rs[p]]&nbsp;+ 1;
p = q;
}
inline void maintain(int&amp; p, bool dir)&nbsp;{
if (dir)&nbsp;{
if (sz[ls[p]]&nbsp;&gt; sz[rs[p]]&nbsp;+ 1)
rRot(p);
}
else
if (sz[ls[p]]&nbsp;+ 1 &lt; sz[rs[p]])
lRot(p);
}
void ins(int&amp; p, int v)&nbsp;{
if (!p)&nbsp;{
p =&nbsp;++ tn;
ls[p]&nbsp;= 0;
rs[p]&nbsp;= 0;
sz[p]&nbsp;= 1;
vl[p]&nbsp;= v;
}
else {
if (v&nbsp;&lt; vl[p])
ins(ls[p], v);
else
ins(rs[p], v);
++ sz[p];
maintain(p, v &lt; vl[p]);
}
}
int cntLower(int p, int v)&nbsp;{
if (!p)
return 0;
else if (vl[p]&nbsp;&lt;= v)
return sz[ls[p]]&nbsp;+ 1 + cntLower(rs[p], v);
else
return cntLower(ls[p], v);
}
};
void dispNums()&nbsp;{
mx = 0;
sort(rx, rx + n + m, cmpP);
for (int i = 0, l =&nbsp;*rx[0]&nbsp;- 1; i &lt; n + m;&nbsp;++ i)
if (*rx[i]&nbsp;== l)
*rx[i]&nbsp;= mx;
else
l =&nbsp;*rx[i],&nbsp;*rx[i]&nbsp;=&nbsp;++ mx;
my = 0;
sort(ry, ry + n + m, cmpP);
for (int i = 0, l =&nbsp;*ry[0]&nbsp;- 1; i &lt; n + m;&nbsp;++ i)
if (*ry[i]&nbsp;== l)
*ry[i]&nbsp;= my;
else
l =&nbsp;*ry[i],&nbsp;*ry[i]&nbsp;=&nbsp;++ my;
}
void sov()&nbsp;{
sbt :: init();
memset(t, 0, sizeof(t));
for (int i = 0, j = 0; j &lt; m;&nbsp;++ j)&nbsp;{
while (i&nbsp;&lt; n &amp;&amp; a[i]. x &lt;= q[j]. x)&nbsp;{
for (int p = a[i]. y; p &lt;= my; p +=&nbsp;(p&nbsp;&amp;&nbsp;-p))
sbt :: ins(t[p], a[i]. h);
++ i;
}
int l = 0, r = maxv;
while (l&nbsp;&lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
int cnt = 0;
for (int p = q[j]. y; p; p -=&nbsp;(p&nbsp;&amp;&nbsp;-p))
cnt += sbt :: cntLower(t[p], mid);
if (cnt&nbsp;&gt;= q[j]. k)
r = mid;
else
l = mid + 1;
}
if (l&nbsp;== maxv)
ans[q[j]. n]&nbsp;=&nbsp;-1;
else
ans[q[j]. n]&nbsp;= l;
}
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
