s += t[p], p -=&nbsp;(p&nbsp;&amp;&nbsp;-p);
return s;
}
void btChg(int* t, int p, int v)&nbsp;{
while (p&nbsp;&lt;= n)
t[p]&nbsp;+= v, p +=&nbsp;(p&nbsp;&amp;&nbsp;-p);
}
#define vof(x)&nbsp;((x)?(x-&gt;v):0)
