p-&gt; v = vof(q)&nbsp;+ v0;
if (p0&nbsp;&lt;= mid)&nbsp;{
p-&gt; rs = rson(q);
q = lson(q);
p-&gt; ls = sp ++;
p = p-&gt; ls;
r = mid;
}
else {
p-&gt; ls = lson(q);
q = rson(q);
p-&gt; rs = sp ++;
p = p-&gt; rs;
l = mid + 1;
}
}
p-&gt; v = vof(q)&nbsp;+ v0;
return s;
}
int sgtQryLower(seg* p, int v)&nbsp;{
int l = 1, r = n, s = 0;
while (l&nbsp;&lt; r &amp;&amp; p)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (v&nbsp;&gt; mid)&nbsp;{
s += vof(lson(p));
p = rson(p);
l = mid + 1;
}
else {
p = lson(p);
r = mid;
}
}
return s;
}
int query(int l, int r)&nbsp;{
