ans += sgtQryLower(rt[r + 1], a[i])&nbsp;- clo[i];
}
else {
for (int i = lb; i &lt;= rb;&nbsp;++ i)&nbsp;{
ans += bi[i];
ans += bb[i][rb];
}
for (int i = l; fb[i]&nbsp;&lt; lb;&nbsp;++ i)
ans += sgtQryLower(rt[r + 1], a[i])&nbsp;- clo[i];
if (lb)
for (int i =&nbsp;(rb&nbsp;+ 1)&nbsp;* bs; i &lt;= r;&nbsp;++ i)
ans += ff[rb][i]&nbsp;- ff[lb - 1][i];
else
for (int i =&nbsp;(rb&nbsp;+ 1)&nbsp;* bs; i &lt;= r;&nbsp;++ i)
ans += ff[rb][i];
ans += bp[fb[r]][r - bs * fb[r]];
}
