clo[i]&nbsp;= sgtQryLower(rt[i], a[i]);
if (fb[i]&nbsp;^ fb[i + 1])
memset(t, 0, sizeof(t));
}
tb = fb[n - 1];
for (int i = 0; i &lt; tb;&nbsp;++ i)&nbsp;{
int s = 0, c = 0;
memset(t, 0, sizeof(t));
for (int j = i * bs; fb[j]&nbsp;== fb[i * bs];&nbsp;++ j)
btChg(t, a[j], 1),&nbsp;++ c;
for (int j =&nbsp;(i&nbsp;+ 1)&nbsp;* bs; j &lt; n;&nbsp;++ j)&nbsp;{
s += c - btQry(t, a[j]);
if (fb[j]&nbsp;^ fb[j + 1])
bb[i][fb[j]]&nbsp;= s;
}
}
for (int i = 0; i &lt; tb;&nbsp;++ i)&nbsp;{
int c = 0;
memset(t, 0, sizeof(t));
for (int j = 0; fb[j]&nbsp;&lt;= fb[i * bs];&nbsp;++ j)
btChg(t, a[j], 1),&nbsp;++ c;
for (int j =&nbsp;(i&nbsp;+ 1)&nbsp;* bs; j &lt; n;&nbsp;++ j)
ff[i][j]&nbsp;= c - btQry(t, a[j]);
}
lans = 0;
readInt(m);
while (m&nbsp;--)&nbsp;{
int l, r;
readInt(l);
readInt(r);
l ^= lans;
r ^= lans;
-- l;
-- r;
printf(&quot;%d\n&quot;,&nbsp;(lans = query(l, r)));
}
}

