#endif
struct seg {
int l, r, v, p;
seg *ls,&nbsp;*rs;
};
const int maxn = 500009;
const int inf = 0x3f3f3f3f;
int n, m, h, a[maxn], s[maxn],&nbsp;*r[maxn], t[maxn];
qw ans;
seg *rt,&nbsp;*sp;
inline bool cmpP(const int* a, const int* b)&nbsp;{
return *a&nbsp;&lt;&nbsp;*b;
}
int btQry(int* t, int p)&nbsp;{
int s = 0;
while (p)
s += t[p], p -=&nbsp;(p&nbsp;&amp;&nbsp;-p);
return s;
}
void btChg(int* t, int p, int v)&nbsp;{
while (p&nbsp;&lt; maxn)
t[p]&nbsp;+= v, p +=&nbsp;(p&nbsp;&amp;&nbsp;-p);
}
#define mid(p)&nbsp;((p-&gt;l+p-&gt;r)&gt;&gt;1)
seg* sgtBuild(int l, int r)&nbsp;{
seg* p = sp ++;
p-&gt; l = l;
p-&gt; r = r;
p-&gt; v = inf;
if (l&nbsp;+ 1 &lt; r)&nbsp;{
p-&gt; ls = sgtBuild(l, mid(p));
p-&gt; rs = sgtBuild(mid(p), r);
}
else
p-&gt; p = l;
return p;
}
void sgtChg(seg* p, int p0, int v0)&nbsp;{
if (p-&gt; l + 1 == p-&gt; r)
p-&gt; v = v0;
else {
if (p0&nbsp;&lt; mid(p))
sgtChg(p-&gt; ls, p0, v0);
else
sgtChg(p-&gt; rs, p0, v0);
if (p-&gt; rs-&gt; v &lt;= p-&gt; ls-&gt; v)&nbsp;{
p-&gt; v = p-&gt; rs-&gt; v;
p-&gt; p = p-&gt; rs-&gt; p;
}
else {
p-&gt; v = p-&gt; ls-&gt; v;
p-&gt; p = p-&gt; ls-&gt; p;
}
}
}
int sgtLower(seg* p, int l, int v)&nbsp;{
if (l&nbsp;== p-&gt; l)
return (p-&gt; v &lt;= v)&nbsp;? p-&gt; p : inf;
else if (l&nbsp;&gt;= mid(p))
return sgtLower(p-&gt; rs, l, v);
else {
int x = sgtLower(p-&gt; ls, l, v);
if (x&nbsp;&lt; inf)
return x;
else
return (p-&gt; rs-&gt; v &lt;= v)&nbsp;? p-&gt; rs-&gt; p : inf;
}
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
sp = new seg[maxn * 3];
readInt(n);
readInt(m);
rt = sgtBuild(1, n + 1);
for (int i = 1; i &lt;= n;&nbsp;++ i)&nbsp;{
readInt(a[i]);
r[i - 1]&nbsp;= a + i;
}
sort(r, r + n, cmpP);
for (int i = 0, l =&nbsp;*r[0]&nbsp;- 1, v = 0; i &lt; n;&nbsp;++ i)
if (*r[i]&nbsp;== l)
*r[i]&nbsp;= v;
else
l =&nbsp;*r[i],&nbsp;*r[i]&nbsp;=&nbsp;++ v;
ans = 0;
for (int i = n; i;&nbsp;-- i)&nbsp;{
sgtChg(rt, i, a[i]);
s[i]&nbsp;= btQry(t, a[i]&nbsp;- 1);
ans += s[i];
btChg(t, a[i], 1);
}
printf(lld &quot;\n&quot;, ans);
while (m&nbsp;--)&nbsp;{
int l, p;
readInt(l);
int h = a[l];
if (h&nbsp;&lt; inf)
while ((p&nbsp;= sgtLower(rt, l, h))&nbsp;&lt; inf)&nbsp;{
ans -= s[p];
a[p]&nbsp;= inf;
sgtChg(rt, p, a[p]);
}
printf(lld &quot;\n&quot;, ans);
}
}
