inline cplx()&nbsp;{
r = 0, i = 0;
}
inline cplx(double r0, double i0)&nbsp;{
r = r0, i = i0;
}
inline cplx operator =(const cplx&amp; a)&nbsp;{
r = a. r, i = a. i;
return *this;
}
inline cplx operator +(const cplx&amp; a)&nbsp;{
return cplx(r + a. r, i + a. i);
}
inline cplx operator -(const cplx&amp; a)&nbsp;{
return cplx(r - a. r, i - a. i);
}
inline cplx operator *(const cplx&amp; a)&nbsp;{
return cplx(r * a. r - i * a. i, r * a. i + i * a. r);
}
};
#define pow2(x)&nbsp;(1&lt;&lt;(x))
