for (int i = 1, j =&nbsp;(n&nbsp;&gt;&gt; 1), k; i &lt; n - 1;&nbsp;++ i)&nbsp;{
if (i&nbsp;&lt; j)
swap(a[i], a[j]);
k = n &gt;&gt; 1;
