content:
很久之前就看过的题。不过一直没有勇气去做。爱真的需要勇气。
mex这个函数的性质比较奇妙。一端确定的话一定是单增的。两段和起来也一定是增加的。
可以很方便地求出从1到任何一个位置的mex。考虑把询问离线。按左端点排序。如果去掉一个数，那么对于右端点在（从这个数到下一个等于这个数的位置）这一段里的询问，它的值至多是这个数。
所以用线段树维护区修单查维护一下区间最小值就好了。注意如果没有下一个数了那么右端点是n。
据说要离散不过被我用map给水过去了。
#include &lt;cstdio&gt;
#include &lt;cctype&gt;
#include &lt;memory.h&gt;
#include &lt;map&gt;
#include &lt;algorithm&gt;
using namespace std;
#define readInt(_s_)&nbsp;{\
int _d_;\
_s_ = 0;\
while (!isdigit(_d_&nbsp;= getchar()));\
while ((_s_&nbsp;= _s_ * 10 + _d_ - 48), isdigit(_d_ = getchar()));\
}
struct seg {
int l, r, z;
seg *ls,&nbsp;*rs;
};
struct query {
int l, r, n;
};
inline bool cmpQuery(const query&amp; a, const query&amp; b)&nbsp;{
return a. l &lt; b. l;
}
typedef pair &lt;int, int&gt; rpair;
const int maxn = 200009;
const int inf = 0x3f3f3f3f;
int n, m, a[maxn], tmp[maxn], nv[maxn], m0[maxn], ans[maxn];
bool fv[maxn];
seg *rt,&nbsp;*sp;
query q[maxn];
map &lt;int, int&gt; rp;
inline bool cmpTmp(const int&amp; x, const int&amp; y)&nbsp;{
return (a[x]&nbsp;&lt; a[y])&nbsp;||&nbsp;(a[x]&nbsp;== a[y]&nbsp;&amp;&amp; x &lt; y);
}
#define mid(p)&nbsp;((p-&gt;l+p-&gt;r)&gt;&gt;1)
seg* sgtBuild(int l, int r)&nbsp;{
seg* p = sp ++;
p-&gt; l = l;
p-&gt; r = r;
p-&gt; z = inf;
if (l&nbsp;+ 1 &lt; r)&nbsp;{
p-&gt; ls = sgtBuild(l, mid(p));
p-&gt; rs = sgtBuild(mid(p), r);
}
else
p-&gt; z = m0[l];
return p;
}
void sgtChg(seg* p, int l, int r, int v)&nbsp;{
if (p-&gt; l == l &amp;&amp; p-&gt; r == r)
p-&gt; z = min(p-&gt; z, v);
else if (r&nbsp;&lt;= mid(p))
sgtChg(p-&gt; ls, l, r, v);
else if (l&nbsp;&gt;= mid(p))
sgtChg(p-&gt; rs, l, r, v);
else {
sgtChg(p-&gt; ls, l, mid(p), v);
sgtChg(p-&gt; rs, mid(p), r, v);
}
}
int sgtQry(seg* p, int p0)&nbsp;{
if (p-&gt; l + 1 == p-&gt; r)
return p-&gt; z;
else if (p0&nbsp;&lt; mid(p))
return min(sgtQry(p-&gt; ls, p0), p-&gt; z);
else
return min(sgtQry(p-&gt; rs, p0), p-&gt; z);
}
void preSeq()&nbsp;{
a[0]&nbsp;=&nbsp;-1;
for (int i = 0; i &lt;= n;&nbsp;++ i)
tmp[i]&nbsp;= i;
sort(tmp, tmp + n + 1, cmpTmp);
m0[n]&nbsp;= 0;
for (int i = 0; i &lt;= n;&nbsp;++ i)&nbsp;{
if (a[tmp[i]]&nbsp;== m0[n])
++ m0[n];
if (i&nbsp;&amp;&amp; a[tmp[i]]&nbsp;&gt; a[tmp[i - 1]])
fv[tmp[i]]&nbsp;= 1;
else
fv[tmp[i]]&nbsp;= 0;
}
nv[n]&nbsp;=&nbsp;-1;
for (int i = n; i;&nbsp;-- i)&nbsp;{
if (!fv[i]&nbsp;|| a[i]&nbsp;&gt; m0[i])
m0[i - 1]&nbsp;= m0[i];
else
m0[i - 1]&nbsp;= a[i];
map &lt;int, int&gt;&nbsp;:: iterator it = rp. find(a[i]);
if (it&nbsp;== rp. end())&nbsp;{
nv[i]&nbsp;=&nbsp;-1;
rp. insert(rpair(a[i], i));
}
else {
nv[i]&nbsp;= it-&gt; second;
it-&gt; second = i;
}
}
sp = new seg[maxn * 3];
rt = sgtBuild(1, n + 1);
}
void rmvNum(int i)&nbsp;{
if (nv[i]&nbsp;&gt;&nbsp;-1)
sgtChg(rt, i, nv[i], a[i]);
else
sgtChg(rt, i, n + 1, a[i]);
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
readInt(n);
readInt(m);
for (int i = 1; i &lt;= n;&nbsp;++ i)
readInt(a[i]);
for (int i = 0; i &lt; m;&nbsp;++ i)&nbsp;{
readInt(q[i]. l);
readInt(q[i]. r);
q[i]. n = i;
}
sort(q, q + m, cmpQuery);
preSeq();
for (int i = 0, j = 1; i &lt; m;&nbsp;++ i)&nbsp;{
for (; j &lt; q[i]. l;&nbsp;++ j)
rmvNum(j);
ans[q[i]. n]&nbsp;= sgtQry(rt, q[i]. r);
}
for (int i = 0; i &lt; m;&nbsp;++ i)
printf(&quot;%d\n&quot;, ans[i]);
}

