content:
比较神奇的一道树的题。
做法是离线。想了好久的在线啊。
把询问拆成0~l-1和0~r。挨个从0开始加点。加点就是把从根到这个点的所有点权+1，询问就是询问这个点到根的点权和。好机智的做法。
代码还比较舒服。dfs+树链剖分+树状数组。
#include &lt;cstdio&gt;
#include &lt;memory.h&gt;
#include &lt;algorithm&gt;
using namespace std;
struct edge {
int t;
edge *next;
};
struct query {
int p, v, n, c;
inline query(int p0 = 0, int v0 = 0, int n0 = 0, int c0 = 0)&nbsp;{
p = p0, v = v0, n = n0, c = c0;
}
};
const int maxn = 50009;
const int mod = 201314;
void btChg(int* t, int p, int v)&nbsp;{
while (p&nbsp;&lt; maxn)
(t[p]&nbsp;+= v)&nbsp;%= mod, p +=&nbsp;(p&nbsp;&amp;&nbsp;-p);
}
int btQry(int* t, int p)&nbsp;{
int s = 0;
while (p)
(s += t[p])&nbsp;%= mod, p -=&nbsp;(p&nbsp;&amp;&nbsp;-p);
return s;
}
inline bool cmpQuery(const query&amp; a, const query&amp; b)&nbsp;{
return a. p &lt; b. p;
}
edge *head[maxn],&nbsp;*ep;
query q[maxn * 2];
int n, m, fa[maxn], ans[maxn];
int tc, sz[maxn], fc[maxn], ch[maxn], fs[maxn];
int dfo[maxn], dfb[maxn];
int t[maxn], s[maxn];
inline void addEdge(int u, int v)&nbsp;{
ep-&gt; t = v;
ep-&gt; next = head[u];
head[u]&nbsp;= ep ++;
}
void dfs()&nbsp;{
static int stc[maxn];
int tstc = 1, dfn = 0;
stc[1]&nbsp;= 0;
while (tstc)&nbsp;{
int p = stc[tstc --];
dfo[++ dfn]&nbsp;= p;
dfb[p]&nbsp;= dfn;
for (edge* e = head[p]; e; e = e-&gt; next)
if (!dfb[e-&gt; t])
stc[++ tstc]&nbsp;= e-&gt; t;
}
tc = 0;
for (int i = n; i;&nbsp;-- i)&nbsp;{
int p = dfo[i], x =&nbsp;-1;
sz[p]&nbsp;= 1;
for (edge* e = head[p]; e; e = e-&gt; next)
if (dfb[e-&gt; t]&nbsp;&gt; dfb[p])&nbsp;{
sz[p]&nbsp;+= sz[e-&gt; t];
if (x&nbsp;==&nbsp;-1&nbsp;|| sz[e-&gt; t]&nbsp;&gt; sz[x])
x = e-&gt; t;
}
fs[p]&nbsp;= x;
if (x&nbsp;==&nbsp;-1)&nbsp;{
fc[p]&nbsp;=&nbsp;++ tc;
ch[fc[p]]&nbsp;= p;
}
else {
fc[p]&nbsp;= fc[x];
ch[fc[p]]&nbsp;= p;
}
}
tstc = 1;
stc[1]&nbsp;= 0;
dfn = 0;
memset(dfb, 0, sizeof(dfb));
while (tstc)&nbsp;{
int p = stc[tstc --];
dfo[++ dfn]&nbsp;= p;
dfb[p]&nbsp;= dfn;
for (edge* e = head[p]; e; e = e-&gt; next)
if (e-&gt; t ^ fs[p])
stc[++ tstc]&nbsp;= e-&gt; t;
if (fs[p]&nbsp;&gt;&nbsp;-1)
stc[++ tstc]&nbsp;= fs[p];
}
}
void segChg(int l, int r, int v)&nbsp;{
btChg(t, l, v);
btChg(s, l, l * v % mod);
btChg(t, r + 1, mod - v);
btChg(s, r + 1, mod -&nbsp;(r&nbsp;+ 1)&nbsp;* v % mod);
}
int segQry(int l, int r)&nbsp;{
return ((btQry(t, r)&nbsp;*&nbsp;(r + 1)&nbsp;% mod - btQry(s, r)\
- btQry(t, l - 1)&nbsp;* l % mod + btQry(s, l - 1))&nbsp;% mod + mod)&nbsp;% mod;
}
void ins(int p)&nbsp;{
while (p&nbsp;^&nbsp;-1)&nbsp;{
segChg(dfb[ch[fc[p]]], dfb[p], 1);
p = fa[ch[fc[p]]];
}
}
int qry(int p)&nbsp;{
int s = 0;
while (p&nbsp;^&nbsp;-1)&nbsp;{
(s += segQry(dfb[ch[fc[p]]], dfb[p]))&nbsp;%= mod;
p = fa[ch[fc[p]]];
}
return s;
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
memset(head, 0, sizeof(head));
ep = new edge[maxn * 2];
scanf(&quot;%d%d&quot;,&nbsp;&amp;n,&nbsp;&amp;m);
fa[0]&nbsp;=&nbsp;-1;
for (int i = 1; i &lt; n;&nbsp;++ i)&nbsp;{
scanf(&quot;%d&quot;, fa + i);
addEdge(fa[i], i);
}
for (int i = 0; i &lt; m;&nbsp;++ i)&nbsp;{
int l, r, p;
scanf(&quot;%d%d%d&quot;,&nbsp;&amp;l,&nbsp;&amp;r,&nbsp;&amp;p);
q[i &lt;&lt; 1]&nbsp;= query(l - 1, p, i,&nbsp;-1);
q[(i &lt;&lt; 1)&nbsp;| 1]&nbsp;= query(r, p, i, 1);
}
sort(q, q + m * 2, cmpQuery);
dfs();
for (int i = 0, j = 0; j &lt; m * 2;)&nbsp;{
for (; i &lt;= q[j]. p;&nbsp;++ i)
ins(i);
for (; j &lt; m * 2 &amp;&amp; q[j]. p == i - 1;&nbsp;++ j)
ans[q[j]. n]&nbsp;+= q[j]. c * qry(q[j]. v);
}
for (int i = 0; i &lt; m;&nbsp;++ i)
printf(&quot;%d\n&quot;,&nbsp;(ans[i]&nbsp;% mod + mod)&nbsp;% mod);
}

