}
const int maxn = 80009;
const int maxv = 1e8;
namespace treap {
struct node {
int ls, rs, v, w, sz;
};
const int maxnd = 80009 * 19;
node a[maxnd];
int tn, nst[maxnd];
void init()&nbsp;{
srand(239407234);
a[0]. sz = 0;
tn = 0;
for (int i = 1; i &lt; maxnd;&nbsp;++ i)
nst[++ tn]&nbsp;= i;
}
inline int newNode(int v)&nbsp;{
int p = nst[tn --];
a[p]. ls = 0;
a[p]. rs = 0;
a[p]. v = v;
a[p]. w = rand()&nbsp;|&nbsp;(rand()&nbsp;&lt;&lt; 16);
a[p]. sz = 1;
return p;
}
inline void update(const int&amp; p)&nbsp;{
a[p]. sz = a[a[p]. ls]. sz + a[a[p]. rs]. sz + 1;
}
inline void lRot(int&amp; p)&nbsp;{
int q = a[p]. rs;
a[p]. rs = a[q]. ls;
a[q]. ls = p;
update(p);
update(q);
p = q;
}
inline void rRot(int&amp; p)&nbsp;{
int q = a[p]. ls;
a[p]. ls = a[q]. rs;
a[q]. rs = p;
update(p);
update(q);
p = q;
}
inline void maintain(int&amp; p, bool d)&nbsp;{
if (d)&nbsp;{
if (a[a[p]. ls]. w &gt; a[p]. w)
rRot(p);
}
else
if (a[a[p]. rs]. w &gt; a[p]. w)
lRot(p);
}
inline void ins(int&amp; p, int v)&nbsp;{
if (!p)
p = newNode(v);
else {
if (v&nbsp;&lt; a[p]. v)
ins(a[p]. ls, v);
else
ins(a[p]. rs, v);
update(p);
maintain(p, v &lt; a[p]. v);
}
}
inline void ers(int&amp; p, int v)&nbsp;{
if (!p)
return;
else if (a[p]. v == v)&nbsp;{
if (!a[p]. ls)
p = a[p]. rs;
else if (!a[p]. rs)
p = a[p]. ls;
else {
int q = a[p]. ls;
while (a[q]. rs)
q = a[q]. rs;
a[p]. v = a[q]. v;
ers(a[p]. ls, a[p]. v);
update(p);
}
}
else {
if (v&nbsp;&lt; a[p]. v)
ers(a[p]. ls, v);
else
ers(a[p]. rs, v);
update(p);
}
}
inline int cnt(int p, int v)&nbsp;{
if (!p)
return 0;
else if (v&nbsp;&lt;= a[p]. v)
return cnt(a[p]. ls, v);
else
return a[a[p]. ls]. sz + 1 + cnt(a[p]. rs, v);
}
};
int n, q, v[maxn];
int tc, d[maxn], fa[maxn], sz[maxn], ch[maxn], fc[maxn], cl[maxn];
seg *rt[maxn],&nbsp;*sp;
edge *ep,&nbsp;*head[maxn];
inline void addEdge(int u, int v)&nbsp;{
ep-&gt; t = v;
ep-&gt; next = head[u];
head[u]&nbsp;= ep ++;
}
#define mid(p)&nbsp;((p-&gt;l+p-&gt;r)&gt;&gt;1)
inline seg* sgtBuild(int l, int r)&nbsp;{
seg* p = sp ++;
p-&gt; l = l;
p-&gt; r = r;
p-&gt; v = 0;
if (l&nbsp;+ 1 &lt; r)&nbsp;{
p-&gt; ls = sgtBuild(l, mid(p));
p-&gt; rs = sgtBuild(mid(p), r);
}
return p;
}
inline void sgtChg(seg* p, int p0, int v, int ty)&nbsp;{
if (ty&nbsp;== 1)
treap :: ins(p-&gt; v, v);
else
treap :: ers(p-&gt; v, v);
if (p-&gt; l + 1 == p-&gt; r)
return;
else if (p0&nbsp;&lt; mid(p))
sgtChg(p-&gt; ls, p0, v, ty);
else
sgtChg(p-&gt; rs, p0, v, ty);
}
inline int sgtQry(seg* p, int l, int r, int v)&nbsp;{
if (l&nbsp;&gt;= r)
return 0;
else if (p-&gt; l == l &amp;&amp; p-&gt; r == r)
return treap :: cnt(p-&gt; v, v);
else if (r&nbsp;&lt;= mid(p))
return sgtQry(p-&gt; ls, l, r, v);
else if (l&nbsp;&gt;= mid(p))
return sgtQry(p-&gt; rs, l, r, v);
else
return sgtQry(p-&gt; ls, l, mid(p), v)&nbsp;+ sgtQry(p-&gt; rs, mid(p), r, v);
}
#define cpos(_p_)&nbsp;(d[_p_]-d[ch[fc[_p_]]])
void divide()&nbsp;{
static int q[maxn];
int hd = 0, tl = 1;
memset(d, 0, sizeof(d));
d[1]&nbsp;= 1;
fa[1]&nbsp;= 0;
q[0]&nbsp;= 1;
while (hd&nbsp;&lt; tl)&nbsp;{
int p = q[hd ++];
for (edge* e = head[p]; e; e = e-&gt; next)
if (!d[e-&gt; t])&nbsp;{
d[e-&gt; t]&nbsp;= d[p]&nbsp;+ 1;
fa[e-&gt; t]&nbsp;= p;
q[tl ++]&nbsp;= e-&gt; t;
}
}
tc = 0;
for (int ti = tl - 1; ti &gt;= 0;&nbsp;-- ti)&nbsp;{
int p = q[ti], x =&nbsp;-1;
sz[p]&nbsp;= 1;
for (edge* e = head[p]; e; e = e-&gt; next)
if (fa[e-&gt; t]&nbsp;== p)&nbsp;{
sz[p]&nbsp;+= sz[e-&gt; t];
if (x&nbsp;==&nbsp;-1&nbsp;|| sz[e-&gt; t]&nbsp;&gt; sz[x])
x = e-&gt; t;
}
if (x&nbsp;==&nbsp;-1)&nbsp;{
fc[p]&nbsp;=&nbsp;++ tc;
ch[fc[p]]&nbsp;= p;
cl[fc[p]]&nbsp;= 1;
}
else {
fc[p]&nbsp;= fc[x];
ch[fc[p]]&nbsp;= p;
++ cl[fc[p]];
}
}
sp = new seg[maxn * 4];
for (int i = 1; i &lt;= tc;&nbsp;++ i)
rt[i]&nbsp;= sgtBuild(0, cl[i]);
for (int i = 1; i &lt;= n;&nbsp;++ i)
sgtChg(rt[fc[i]], cpos(i), v[i], 1);
}
int LCA(int u, int v)&nbsp;{
while (fc[u]&nbsp;^ fc[v])
if (d[ch[fc[u]]]&nbsp;&gt; d[ch[fc[v]]])
u = fa[ch[fc[u]]];
else
v = fa[ch[fc[v]]];
if (d[u]&nbsp;&lt; d[v])
return u;
else
return v;
}
int cntChain(int u, int a, int v)&nbsp;{
int s = 0;
while (fc[u]&nbsp;^ fc[a])&nbsp;{
s += sgtQry(rt[fc[u]], 0, cpos(u)&nbsp;+ 1, v);
u = fa[ch[fc[u]]];
}
if (u&nbsp;^ a)
s += sgtQry(rt[fc[u]], cpos(a)&nbsp;+ 1, cpos(u)&nbsp;+ 1, v);
return s;
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
treap :: init();
memset(head, 0, sizeof(head));
ep = new edge[maxn * 2];
readInt(n);
readInt(q);
for (int i = 1; i &lt;= n;&nbsp;++ i)
readInt(v[i]);
for (int i = 0; i &lt; n - 1;&nbsp;++ i)&nbsp;{
int u, v;
readInt(u);
readInt(v);
addEdge(u, v);
addEdge(v, u);
}
divide();
while (q&nbsp;--)&nbsp;{
int k, a, b;
readInt(k);
readInt(a);
readInt(b);
if (!k)&nbsp;{
sgtChg(rt[fc[a]], cpos(a), v[a],&nbsp;-1);
v[a]&nbsp;= b;
sgtChg(rt[fc[a]], cpos(a), v[a], 1);
}
else {
int l = 0, r = maxv, c = LCA(a, b);
if (d[a]&nbsp;+ d[b]&nbsp;- d[c]&nbsp;* 2 + 1 &lt; k)
puts(&quot;invalid request!&quot;);
else {
k = d[a]&nbsp;+ d[b]&nbsp;- d[c]&nbsp;* 2 + 2 - k;
while (l&nbsp;&lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r + 1)&nbsp;&gt;&gt; 1;
if (cntChain(a, c, mid)&nbsp;+ cntChain(b, fa[c], mid)&nbsp;&gt;= k)
r = mid - 1;
else
l = mid;
}
printf(&quot;%d\n&quot;, l);
}
}
}
}

