do\
_s_ = getchar();\
while (_s_&nbsp;!=&nbsp;'I'&nbsp;&amp;&amp; _s_ !=&nbsp;'D'&nbsp;&amp;&amp; _s_ !=&nbsp;'R'&nbsp;&amp;&amp; _s_ !=&nbsp;'Q');\
}
const int maxn = 200009;
struct node {
int vl, ls, rs, pt, sz, sl, sr, sm, s;
};
int v0[maxn];
int n, m, rt, tn, cr;
node tree[maxn];
inline void initDat(const int&amp; p, const int&amp; v0)&nbsp;{
tree[p]. sl = v0;
tree[p]. sr = v0;
tree[p]. sm = v0;
tree[p]. s = v0;
}
inline void mergeDat(const int&amp; p, const int&amp; a, const int&amp; b)&nbsp;{
int nl = max(tree[a]. sl, tree[a]. sm + tree[b]. sl);
int nr = max(tree[b]. sr, tree[b]. sm + tree[a]. sr);
int nm = tree[a]. sm + tree[b]. sm;
int nx = max(max(tree[a]. s, tree[b]. s), tree[a]. sr + tree[b]. sl);
tree[p]. sl = nl;
tree[p]. sr = nr;
tree[p]. sm = nm;
tree[p]. s = nx;
}
int newNode(int v0)&nbsp;{
++ tn;
tree[tn]. vl = v0;
tree[tn]. ls = 0;
tree[tn]. rs = 0;
tree[tn]. sz = 1;
initDat(tn, v0);
return tn;
}
#define update(_p_)&nbsp;{\
tree[_p_]. sz = tree[tree[_p_]. ls]. sz + tree[tree[_p_]. rs]. sz + 1;\
initDat(_p_, tree[_p_]. vl);\
if (tree[_p_]. ls)\
mergeDat(_p_, tree[_p_]. ls, _p_);\
if (tree[_p_]. rs)\
mergeDat(_p_, _p_, tree[_p_]. rs);\
}
inline void lRot(int q)&nbsp;{
int p = tree[q]. pt, a = tree[p]. pt;
if (tree[q]. rs)
tree[tree[q]. rs]. pt = p;
tree[p]. ls = tree[q]. rs;
tree[q]. rs = p;
tree[q]. pt = a;
tree[p]. pt = q;
if (a)&nbsp;{
if (p&nbsp;== tree[a]. ls)
tree[a]. ls = q;
else
tree[a]. rs = q;
}
update(p);
update(q);
}
inline void rRot(int q)&nbsp;{
int p = tree[q]. pt, a = tree[p]. pt;
if (tree[q]. ls)
tree[tree[q]. ls]. pt = p;
tree[p]. rs = tree[q]. ls;
tree[q]. ls = p;
tree[q]. pt = a;
tree[p]. pt = q;
if (a)&nbsp;{
if (p&nbsp;== tree[a]. ls)
tree[a]. ls = q;
else
tree[a]. rs = q;
}
update(p);
update(q);
}
void splay(int q)&nbsp;{
while (tree[q]. pt)&nbsp;{
int p = tree[q]. pt, a = tree[p]. pt;
if (!a&nbsp;||&nbsp;!tree[a]. pt)&nbsp;{
if (q&nbsp;== tree[p]. ls)
lRot(q);
else
rRot(q);
}
else {
if (p&nbsp;== tree[a]. ls)&nbsp;{
if (q&nbsp;== tree[p]. ls)&nbsp;{
lRot(p);
lRot(q);
}
else {
rRot(q);
lRot(q);
}
}
else {
if (q&nbsp;== tree[p]. rs)&nbsp;{
rRot(p);
rRot(q);
}
else {
lRot(q);
rRot(q);
}
}
}
}
}
int makeTree(int l, int r)&nbsp;{
if (l&nbsp;&gt; r)
return 0;
int x =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
int p = newNode(v0[x]);
tree[p]. ls = makeTree(l, x - 1);
tree[tree[p]. ls]. pt = p;
tree[p]. rs = makeTree(x + 1, r);
tree[tree[p]. rs]. pt = p;
update(p);
return p;
}
int kth(int p, int k)&nbsp;{
while (p)
if (tree[tree[p]. ls]. sz + 1 == k)
break;
else if (tree[tree[p]. ls]. sz &gt;= k)
p = tree[p]. ls;
else
k -= tree[tree[p]. ls]. sz + 1, p = tree[p]. rs;
return p;
}
int query(int rt, int l, int r)&nbsp;{
int p = kth(rt, l), q = kth(rt, r + 2);
splay(p);
splay(q);
cr = q;
return tree[tree[p]. rs]. s;
}
void dispTree(int p, bool ed = 1)&nbsp;{
if (!p)
return;
dispTree(tree[p]. ls, 0);
printf(&quot;%d &quot;, tree[p]. vl);
dispTree(tree[p]. rs, 0);
if (ed)
putchar(10);
}
int main()&nbsp;{
#ifndef ONLINE_JUDGE
freopen(&quot;in.txt&quot;,&nbsp;&quot;r&quot;, stdin);
#endif
readInt(n);
rt = 0;
tn = 0;
for (int i = 1; i &lt;= n;&nbsp;++ i)
readInt(v0[i]);
v0[0]&nbsp;= 0;
v0[n + 1]&nbsp;= 0;
cr = makeTree(0, n + 1);
readInt(m);
while (m&nbsp;--)&nbsp;{
char opt;
int p, v, l, r, rt = cr;
readOpt(opt);
//dispTree(cr);
if (opt&nbsp;==&nbsp;'I')&nbsp;{
readInt(p);
readInt(v);
int q = kth(rt, p), u = newNode(v);
splay(q);
cr = q;
if (tree[q]. rs)
tree[tree[q]. rs]. pt = u;
tree[u]. rs = tree[q]. rs;
update(u);
tree[q]. rs = u;
tree[u]. pt = q;
update(q);
if (tree[u]. rs)&nbsp;{
cr = tree[u]. rs;
splay(cr);
}
++ n;
}
else if (opt&nbsp;==&nbsp;'D')&nbsp;{
readInt(p);
int q = kth(rt, p + 1);
