}
else if (opt&nbsp;==&nbsp;'R')&nbsp;{
readInt(p);
readInt(v);
int q = kth(rt, p + 1);
splay(q);
cr = q;
tree[q]. vl = v;
update(q);
}
else if (opt&nbsp;==&nbsp;'Q')&nbsp;{
readInt(l);
readInt(r);
printf(&quot;%d\n&quot;, query(rt, l, r));
}
}
}

