考场上只想到暴力。
如果只是一条链的话怎么乱搞一搞？
如果没有深度限制的话简单的斜率优化+链剖就行了。
有深度限制就把hull扔到线段树里用可持久化栈来维护一下。DFS的时候塞进线段树里，然后完了再扔出来。总的复杂度O(n*log^2(n))，
代码也不怎么复杂。
#include &lt;cstdio&gt;
#include&nbsp;&lt;cctype&gt;
#include&nbsp;&lt;memory.h&gt;
#include&nbsp;&lt;vector&gt;
#include&nbsp;&lt;algorithm&gt;
using namespace std;
struct edge {
int t;
edge* next;
};
typedef long long qw;
typedef long double exf;
#ifdef WIN32
#define lld &quot;%I64d&quot;
#else
#define lld &quot;%lld&quot;
#endif
#define _l (qw)
#define readInt(_s_)&nbsp;{\
int _d_;\
_s_ = 0;\
while (!isdigit(_d_&nbsp;= getchar()));\
while ((_s_&nbsp;= _s_ * 10 + _d_ - 48), isdigit(_d_ = getchar()));\
}
struct oper {
int p, v, t;
oper(int p0 = 0, int v0 = 0, int t0 = 0)&nbsp;{
p = p0, v = v0, t = t0;
}
};
struct phull {
int&nbsp;*s, t;
vector &lt;oper&gt; r;
};
struct seg {
int l, r;
phull d;
seg *ls,&nbsp;*rs;
};
const int maxn = 200009;
const qw inf = 0x3f3f3f3f3f3f3f3fLL;
const exf eps = 1e-8;
qw d[maxn], k[maxn], b[maxn], dl[maxn], f[maxn];
int n, fa[maxn], stc[maxn];
edge *head[maxn],&nbsp;*ep;
seg&nbsp;*rt,&nbsp;*sp;
inline exf getK(int a, int b)&nbsp;{
return ((exf)f[b]&nbsp;- f[a])&nbsp;/&nbsp;((exf)d[b]&nbsp;- d[a]);
}
inline void addEdge(int u, int v)&nbsp;{
ep-&gt; t = v;
ep-&gt; next = head[u];
head[u]&nbsp;= ep ++;
}
#define mid(p)&nbsp;((p-&gt;l+p-&gt;r)&gt;&gt;1)
void phIns(phull&amp; h, int v0)&nbsp;{
if (!h. t)&nbsp;{
h. r. push_back(oper(1, 0, 0));
h. s[h. t = 1]&nbsp;= v0;
}
else if (h. t == 1)&nbsp;{
h. r. push_back(oper(2, 0, 1));
h. s[h. t = 2]&nbsp;= v0;
}
else {
int l = 2, r = h. t;
while (l&nbsp;&lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r + 1)&nbsp;&gt;&gt; 1;
if (getK(h. s[mid - 1], h. s[mid])&nbsp;&gt; getK(h. s[mid - 1], v0)&nbsp;+ eps)
r = mid - 1;
else
l = mid;
}
if (l&nbsp;&gt; 2 || getK(h. s[1], h. s[2])&nbsp;&lt;= getK(h. s[1], v0))
++ l;
h. r. push_back(oper(l, h. s[l], h. t));
h. s[h. t = l]&nbsp;= v0;
}
}
void phCancel(phull&amp; h)&nbsp;{
if (h. r. empty())
return;
oper o =&nbsp;*h. r. rbegin();
h. r. pop_back();
h. s[o. p]&nbsp;= o. v;
h. t = o. t;
}
qw phQry(phull&amp; h, int i)&nbsp;{
int l = 1, r = h. t - 1;
if (!h. t)
return inf;
while (l&nbsp;&lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (getK(h. s[mid], h. s[mid + 1])&nbsp;+ eps &lt; k[i])
l = mid + 1;
else
r = mid;
}
if (l&nbsp;== h. t - 1 &amp;&amp; getK(h. s[l], h. s[l + 1])&nbsp;+ eps &lt; k[i])
++ l;
return f[h. s[l]]&nbsp;+&nbsp;(d[i]&nbsp;- d[h. s[l]])&nbsp;* k[i]&nbsp;+ b[i];
}
seg *sgtBuild(int l, int r)&nbsp;{
seg *p&nbsp;= sp ++;
p-&gt; d. s = new int[r - l + 3];
p-&gt; d. t = 0;
p-&gt; l = l;
p-&gt; r = r;
if (l&nbsp;+ 1 &lt; r)&nbsp;{
p-&gt; ls = sgtBuild(l, mid(p));
p-&gt; rs = sgtBuild(mid(p), r);
}
return p;
}
void sgtChg(seg* p, int p0, int v0)&nbsp;{
if (v0&nbsp;==&nbsp;-1)
phCancel(p-&gt; d);
else
phIns(p-&gt; d, v0);
if (p-&gt; l + 1 &lt; p-&gt; r)&nbsp;{
if (p0&nbsp;&lt; mid(p))
sgtChg(p-&gt; ls, p0, v0);
else
sgtChg(p-&gt; rs, p0, v0);
}
}
qw sgtQry(seg* p, int l, int r, int v0)&nbsp;{
if (l&nbsp;&gt;= r)
return inf;
else if (l&nbsp;== p-&gt; l &amp;&amp; r == p-&gt; r)
return phQry(p-&gt; d, v0);
else if (r&nbsp;&lt;= mid(p))
return sgtQry(p-&gt; ls, l, r, v0);
else if (l&nbsp;&gt;= mid(p))
return sgtQry(p-&gt; rs, l, r, v0);
else
return min(sgtQry(p-&gt; ls, l, mid(p), v0), sgtQry(p-&gt; rs, mid(p), r, v0));
}
qw getAns(int p, int d0)&nbsp;{
int l = 1, r = d0;
while (l&nbsp;&lt; r)&nbsp;{
int mid =&nbsp;(l&nbsp;+ r)&nbsp;&gt;&gt; 1;
if (d[p]&nbsp;- d[stc[mid]]&nbsp;&gt; dl[p])
l = mid + 1;
else
r = mid;
}
return sgtQry(rt, l, d0 + 1, p);
}
void dfs(int p, int d0)&nbsp;{
if (p&nbsp;&gt; 1)
f[p]&nbsp;= getAns(p, d0 - 1);
sgtChg(rt, d0, p);
stc[d0]&nbsp;= p;
for (edge* e = head[p]; e; e = e-&gt; next)
